  tags = {
    Name = "eb-db-subnet-group"
  }
}

# Production RDS Instance
resource "aws_db_instance" "prod_db" {
  identifier             = "prod-db"
  allocated_storage      = 20
  storage_type           = "gp2"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  db_name                = "proddb"
