  name = "example.com"

  tags = {
    Name = "main-hosted-zone"
  }
}

# Route 53 A Record pointing to Elastic Beanstalk environment
resource "aws_route53_record" "app" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "example.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.myenv.cname
    zone_id                = data.aws_elastic_beanstalk_hosted_zone.current.id
    evaluate_target_health = true
  }
}

# Route 53 www subdomain record
resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "www.example.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.myenv.cname
    zone_id                = data.aws_elastic_beanstalk_hosted_zone.current.id
    evaluate_target_health = true
  }
}

# Data source for Elastic Beanstalk hosted zone
data "aws_elastic_beanstalk_hosted_zone" "current" {}

# Outputs
output "route53_zone_id" {
  description = "Route 53 Hosted Zone ID"
  value       = aws_route53_zone.main.zone_id
}

output "route53_nameservers" {
  description = "Route 53 Nameservers"
  value       = aws_route53_zone.main.name_servers
}

output "elastic_beanstalk_cname" {
  description = "Elastic Beanstalk Environment CNAME"
  value       = aws_elastic_beanstalk_environment.myenv.cname
}

output "rds_endpoint" {
  description = "RDS Database Endpoint"
  value       = aws_db_instance.myapp_db.endpoint
}

output "rds_database_name" {
  description = "RDS Database Name"
  value       = aws_db_instance.myapp_db.db_name
}

