  zone_id = aws_route53_zone.main.zone_id
  name    = "example.com"
  type    = "CNAME"
  ttl     = 60

  weighted_routing_policy {
    weight = 50
  }

  set_identifier  = "us-east-1"
  health_check_id = aws_route53_health_check.us_east_1.id
  records         = [aws_elastic_beanstalk_environment.myenv_us_east.cname]
}

# Route 53 Weighted Record for eu-west-1
resource "aws_route53_record" "weighted_eu_west_1" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "example.com"
  type    = "CNAME"
  ttl     = 60

  weighted_routing_policy {
    weight = 50
  }

  set_identifier  = "eu-west-1"
  health_check_id = aws_route53_health_check.eu_west_1.id
  records         = [aws_elastic_beanstalk_environment.myenv_eu_west.cname]
}

