resource "aws_s3_bucket" "codebuild_cache" {
  bucket = "codebuild-example-cache-bucket"
}

# CodeBuild Project
resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "Example CodeBuild project with GitHub source"
  build_timeout = 60
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  cache {
    type     = "S3"
    location = aws_s3_bucket.codebuild_cache.bucket
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "ENVIRONMENT"
      value = "production"
      type  = "PLAINTEXT"
    }

    environment_variable {
      name  = "API_KEY"
      value = "example-api-key-value"
      type  = "PLAINTEXT"
    }

    environment_variable {
      name  = "DATABASE_URL"
      value = "postgres://example.com:5432/db"
      type  = "PLAINTEXT"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/example-repo.git"
    git_clone_depth = 1

    git_submodules_config {
      fetch_submodules = true
    }
  }

  source_version = "main"

  logs_config {
    cloudwatch_logs {
      group_name  = "codebuild-example"
      stream_name = "codebuild-log-stream"
    }
  }

  tags = {
    Name        = "example-codebuild"
    Environment = "production"
  }
}

