    location           = aws_s3_bucket.artifacts.bucket
    name               = "secondary-artifact-1"
    packaging          = "ZIP"
  }

  secondary_artifacts {
    artifact_identifier = "secondary-artifact-2"
    type               = "S3"
    location           = aws_s3_bucket.artifacts.bucket
    name               = "secondary-artifact-2"
    packaging          = "NONE"
