      - mkdir -p primary secondary1 secondary2
      - echo "Primary artifact" > primary/artifact.txt
      - echo "Secondary artifact 1" > secondary1/artifact.txt
      - echo "Secondary artifact 2" > secondary2/artifact.txt
artifacts:
  files:
    - '**/*'
  base-directory: primary
  name: primary-artifact
secondary-artifacts:
  secondary-artifact-1:
