    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketLocation",
          "s3:ListBucket"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:CreateReportGroup",
          "codebuild:CreateReport",
          "codebuild:UpdateReport",
          "codebuild:BatchPutTestCases",
          "codebuild:BatchPutCodeCoverages"
        ]
        Resource = "*"
      }
    ]
  })
}

# S3 Bucket for CodeBuild artifacts
resource "aws_s3_bucket" "codebuild_artifacts" {
  bucket = "codebuild-artifacts-bucket-${data.aws_caller_identity.current.account_id}"
}

# CodeBuild Project with Build Batch Configuration
resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "Example CodeBuild project with build batch configuration"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = 60

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.codebuild_artifacts.bucket
    packaging = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                      = "aws/codebuild/standard:5.0"
    type                       = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode            = false

    environment_variable {
      name  = "EXAMPLE_ENV_VAR"
      value = "example_value"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/repo.git"
    git_clone_depth = 1
    buildspec       = "buildspec.yml"
  }

  build_batch_config {
    service_role    = aws_iam_role.codebuild_role.arn
    combine_artifacts = false

    restrictions {
      maximum_builds_allowed = 100
      compute_types_allowed = [
        "BUILD_GENERAL1_SMALL",
        "BUILD_GENERAL1_MEDIUM"
      ]
    }

    timeout_in_mins = 480
  }

  logs_config {
    cloudwatch_logs {
      status      = "ENABLED"
      group_name  = "/aws/codebuild/example-project"
      stream_name = "build-log"
    }

    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.codebuild_artifacts.id}/build-logs"
    }
  }

  cache {
    type     = "S3"
    location = "${aws_s3_bucket.codebuild_artifacts.bucket}/cache"
  }

  tags = {
    Environment = "Development"
    Project     = "Example"
  }
}

# Data source to get current AWS account ID
data "aws_caller_identity" "current" {}

# Outputs
output "codebuild_project_name" {
  value       = aws_codebuild_project.example.name
  description = "The name of the CodeBuild project"
}

output "codebuild_project_arn" {
  value       = aws_codebuild_project.example.arn
  description = "The ARN of the CodeBuild project"
}

output "codebuild_role_arn" {
  value       = aws_iam_role.codebuild_role.arn
  description = "The ARN of the CodeBuild IAM role"
}

