terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_iam_role" "lex_bot_role" {
  name = "lex-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexRunBotsOnly"
}

resource "aws_lex_intent" "sample_intent" {
  name = "SampleIntent"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "I want to order flowers",
    "I would like to pick up flowers"
  ]

  slot {
    name        = "FlowerType"
    description = "Type of flower to order"
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What type of flowers would you like to order?"
        content_type = "PlainText"
      }
    }
  }
}

resource "aws_lex_bot" "my_bot" {
  name                     = "MyLexBot"
  description              = "Sample Lex Bot created with Terraform"
  idle_session_ttl_in_seconds = 300
  process_behavior         = "BUILD"
  locale                   = "en-US"
  voice_id                 = "Joanna"
  child_directed           = false

  abort_statement {
    message {
      content      = "Sorry, I could not understand. Goodbye."
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2

    message {
      content      = "I didn't understand you, what would you like to do?"
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = aws_lex_intent.sample_intent.name
    intent_version = aws_lex_intent.sample_intent.version
  }

  depends_on = [
    aws_iam_role_policy_attachment.lex_bot_policy
  ]
}

resource "aws_lex_bot_alias" "bot_alias" {
  bot_name    = aws_lex_bot.my_bot.name
  bot_version = aws_lex_bot.my_bot.version
  name        = "Production"
  description = "Production alias for the Lex bot"
}

