  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.pizza_bot_locale.locale_id
  name        = "OrderPizza"
  description = "Intent to order a pizza"

  sample_utterance {
    utterance = "I want to order a pizza"
  }

  sample_utterance {
    utterance = "Order pizza"
  }

  sample_utterance {
    utterance = "I would like a pizza"
  }

  sample_utterance {
    utterance = "Can I get a pizza"
  }

  sample_utterance {
    utterance = "Pizza please"
  }

  slot_priority {
    priority   = 1
    slot_id    = aws_lexv2models_slot.pizza_type_slot.slot_id
  }

  slot_priority {
    priority   = 2
    slot_id    = aws_lexv2models_slot.pizza_size_slot.slot_id
  }

  slot_priority {
    priority   = 3
    slot_id    = aws_lexv2models_slot.delivery_address_slot.slot_id
  }

  confirmation_setting {
    prompt_specification {
      message_group {
        message {
          plain_text_message {
            value = "Great! I have a {PizzaSize} {PizzaType} pizza for delivery to {DeliveryAddress}. Should I place this order?"
          }
        }
      }
      max_retries = 2
    }

    declination_response {
      message_group {
        message {
          plain_text_message {
            value = "Okay, I've cancelled your pizza order. Is there anything else I can help you with?"
          }
        }
      }
    }

    active = true
  }

  fulfillment_code_hook {
    enabled = false
  }

