    }
  }

  conclusion_statement {
    message {
      content      = "Great! Your {PizzaSize} {PizzaType} pizza has been ordered. It will be ready in 30 minutes. Thank you for your order!"
      content_type = "PlainText"
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "You want to order a {PizzaSize} {PizzaType} pizza, is that correct?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I have cancelled your order."
      content_type = "PlainText"
    }
  }

  create_version = true
}

