  }
}

resource "aws_lex_intent" "book_trip" {
  name                    = "BookTrip"
  description             = "Intent to book a trip"
  create_version          = true
  sample_utterances       = [
    "I want to book a trip",
    "Book a vacation",
    "I'd like to travel to {Destination}",
    "Book a trip to {Destination}",
    "I want to go on vacation"
  ]

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Do you want to book a trip to {Destination} departing on {DepartureDate} and returning on {ReturnDate}?"
      content_type = "PlainText"
      group_number = 1
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I have cancelled your trip booking."
      content_type = "PlainText"
      group_number = 1
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }

  slot {
    name        = "Destination"
    description = "Destination city for the trip"
    slot_constraint = "Required"
    slot_type   = "AMAZON.City"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "Where would you like to travel to?"
        content_type = "PlainText"
        group_number = 1
      }

      message {
        content      = "What is your destination city?"
        content_type = "PlainText"
        group_number = 1
      }
    }
  }

  slot {
    name        = "DepartureDate"
    description = "Date of departure"
    slot_constraint = "Required"
    slot_type   = "AMAZON.DATE"
    priority    = 2

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "When would you like to depart?"
        content_type = "PlainText"
        group_number = 1
      }

      message {
        content      = "What is your departure date?"
        content_type = "PlainText"
        group_number = 1
      }
    }
  }

  slot {
    name        = "ReturnDate"
    description = "Date of return"
    slot_constraint = "Required"
    slot_type   = "AMAZON.DATE"
    priority    = 3

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "When would you like to return?"
        content_type = "PlainText"
        group_number = 1
      }

      message {
        content      = "What is your return date?"
        content_type = "PlainText"
        group_number = 1
      }
    }
  }

  slot {
    name        = "Travelers"
    description = "Number of travelers"
    slot_constraint = "Required"
    slot_type   = "AMAZON.NUMBER"
    priority    = 4

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "How many people will be traveling?"
        content_type = "PlainText"
        group_number = 1
      }
    }
  }
}

resource "aws_lex_intent" "cancel_booking" {
  name              = "CancelBooking"
  description       = "Intent to cancel a trip booking"
  create_version    = true
  sample_utterances = [
    "Cancel my trip",
    "I want to cancel my booking",
    "Cancel my reservation",
    "I need to cancel"
  ]

  fulfillment_activity {
    type = "ReturnIntent"
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Are you sure you want to cancel your booking?"
      content_type = "PlainText"
      group_number = 1
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I will not cancel your booking."
      content_type = "PlainText"
      group_number = 1
    }
  }

  conclusion_statement {
    message {
      content      = "Your booking has been cancelled."
      content_type = "PlainText"
      group_number = 1
    }
  }
}

resource "aws_lex_bot_alias" "trip_booking_bot_prod" {
  bot_name    = aws_lex_bot.trip_booking_bot.name
  bot_version = aws_lex_bot.trip_booking_bot.version
  description = "Production alias for trip booking bot"
  name        = "PROD"

  conversation_logs {
    iam_role_arn = aws_iam_role.lex_bot_role.arn

    log_settings {
      destination  = "CLOUDWATCH_LOGS"
      log_type     = "TEXT"
      resource_arn = aws_cloudwatch_log_group.lex_bot_logs.arn
    }
  }
}

resource "aws_cloudwatch_log_group" "lex_bot_logs" {
  name              = "/aws/lex/TripBookingBot"
  retention_in_days = 7
}

resource "aws_iam_role" "lex_bot_role" {
  name = "lex_trip_booking_bot_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lex_bot_policy" {
  name = "lex_bot_cloudwatch_policy"
  role = aws_iam_role.lex_bot_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "${aws_cloudwatch_log_group.lex_bot_logs.arn}:*"
      }
    ]
  })
}

