terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_lex_bot" "pizza_order_bot" {
  name           = "PizzaOrderBot"
  description    = "Bot for ordering pizzas"
  idle_session_ttl_in_seconds = 300
  child_directed = false
  locale         = "en-US"
  voice_id       = "Joanna"

  abort_statement {
    message {
      content      = "Sorry, I am not able to assist at this time"
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2

    message {
      content      = "I didn't understand you, what would you like to do?"
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = aws_lex_intent.order_pizza.version
  }

  intent {
    intent_name    = aws_lex_intent.cancel_order.name
    intent_version = aws_lex_intent.cancel_order.version
  }

  intent {
    intent_name    = aws_lex_intent.check_order_status.name
    intent_version = aws_lex_intent.check_order_status.version
  }

  intent {
    intent_name    = aws_lex_intent.modify_order.name
    intent_version = aws_lex_intent.modify_order.version
  }

  intent {
    intent_name    = aws_lex_intent.view_menu.name
    intent_version = aws_lex_intent.view_menu.version
  }

  process_behavior = "BUILD"
}

resource "aws_lex_intent" "order_pizza" {
  name        = "OrderPizza"
  description = "Intent to order a pizza"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "I would like to order a pizza",
    "Order a pizza",
    "I want to order",
    "Can I get a pizza",
    "Place an order"
  ]

  slot {
    name        = "PizzaSize"
    description = "Size of the pizza"
    slot_constraint = "Required"
    slot_type   = aws_lex_slot_type.pizza_size.name
    slot_type_version = aws_lex_slot_type.pizza_size.version
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What size pizza would you like?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "PizzaType"
    description = "Type of pizza"
    slot_constraint = "Required"
    slot_type   = aws_lex_slot_type.pizza_type.name
    slot_type_version = aws_lex_slot_type.pizza_type.version
    priority    = 2

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What type of pizza would you like?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "Crust"
    description = "Crust type"
    slot_constraint = "Required"
    slot_type   = aws_lex_slot_type.crust_type.name
    slot_type_version = aws_lex_slot_type.crust_type.version
    priority    = 3

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What crust would you like?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Should I order your {PizzaSize} {PizzaType} pizza with {Crust} crust?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I have cancelled your order."
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_intent" "cancel_order" {
  name        = "CancelOrder"
  description = "Intent to cancel a pizza order"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "Cancel my order",
    "I want to cancel",
    "Cancel the pizza",
    "Stop my order",
    "Delete my order"
  ]

  slot {
    name        = "OrderNumber"
    description = "Order number to cancel"
    slot_constraint = "Required"
    slot_type   = "AMAZON.NUMBER"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What is your order number?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Are you sure you want to cancel order {OrderNumber}?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I will not cancel the order."
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_intent" "check_order_status" {
  name        = "CheckOrderStatus"
  description = "Intent to check order status"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "Check my order status",
    "Where is my pizza",
    "Order status",
    "Track my order",
    "What is the status of my order"
  ]

  slot {
    name        = "OrderNumber"
    description = "Order number to check"
    slot_constraint = "Required"
    slot_type   = "AMAZON.NUMBER"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What is your order number?"
        content_type = "PlainText"
      }
    }
  }

  conclusion_statement {
    message {
      content      = "Let me check the status of order {OrderNumber} for you."
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_intent" "modify_order" {
  name        = "ModifyOrder"
  description = "Intent to modify an existing order"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "Modify my order",
    "Change my order",
    "Update my pizza order",
    "I want to change my order",
    "Edit my order"
  ]

  slot {
    name        = "OrderNumber"
    description = "Order number to modify"
    slot_constraint = "Required"
    slot_type   = "AMAZON.NUMBER"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What is your order number?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "Modification"
    description = "What to modify"
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric"
    priority    = 2

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What would you like to modify in your order?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Should I modify order {OrderNumber} with {Modification}?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I will not modify the order."
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_intent" "view_menu" {
