  name = "pizza-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexRunBotsOnly"
}

resource "aws_lexv2models_bot" "pizza_bot" {
  name                        = "KidsPizzaOrderBot"
  description                 = "A fun pizza ordering bot designed for kids"
  idle_session_ttl_in_seconds = 300
  role_arn                    = aws_iam_role.lex_bot_role.arn

  data_privacy {
    child_directed = true
  }

  tags = {
    Environment = "production"
    Purpose     = "Kids Pizza Ordering"
  }
}

resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = "DRAFT"
  locale_id   = "en_US"
  n_lu_intent_confidence_threshold = 0.40

  voice_settings {
    voice_id = "Joanna"
  }
}

resource "aws_lexv2models_intent" "order_pizza" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "OrderPizza"
  description = "Intent to order a pizza"

  sample_utterance {
    utterance = "I want to order a pizza"
  }

  sample_utterance {
    utterance = "Can I get a pizza"
  }

  sample_utterance {
    utterance = "I want pizza"
  }

  sample_utterance {
    utterance = "Order pizza please"
  }

  sample_utterance {
    utterance = "Pizza time"
  }

  slot_priority {
    priority   = 1
    slot_name  = "PizzaSize"
  }

  slot_priority {
    priority   = 2
    slot_name  = "PizzaTopping"
  }

  slot_priority {
    priority   = 3
    slot_name  = "Quantity"
  }

  fulfillment_code_hook {
    enabled = false
  }

  confirmation_setting {
    prompt_specification {
      max_retries                 = 2
      message_selection_strategy  = "Random"

      message_group {
        message {
          plain_text_message {
            value = "Awesome! So you want {Quantity} {PizzaSize} pizza with {PizzaTopping}. Should I place your order?"
          }
        }
      }
    }

    declination_response {
      message_group {
        message {
          plain_text_message {
            value = "No problem! Let me know if you change your mind about pizza!"
          }
        }
      }
    }
  }

  intent_closing_setting {
    closing_response {
      message_group {
        message {
          plain_text_message {
            value = "Great! Your yummy pizza is on the way! It will be ready soon!"
          }
        }
      }
    }
  }
}

