}

# IAM Role for Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "pizza_ordering_lex_bot_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexFullAccess"
}

# IAM Role for Lambda Function
resource "aws_iam_role" "lambda_role" {
  name = "pizza_ordering_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Lambda Function
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function.zip"

  source {
    content  = <<EOF
import json

def lambda_handler(event, context):
    intent_name = event['sessionState']['intent']['name']
    slots = event['sessionState']['intent']['slots']

    if intent_name == 'OrderPizza':
        pizza_type = slots.get('PizzaType', {}).get('value', {}).get('interpretedValue')
        pizza_size = slots.get('PizzaSize', {}).get('value', {}).get('interpretedValue')
        quantity = slots.get('Quantity', {}).get('value', {}).get('interpretedValue')

        message = f"Great! I've ordered {quantity} {pizza_size} {pizza_type} pizza(s) for you. Your order will be ready in 30 minutes."

        return {
            'sessionState': {
                'dialogAction': {
                    'type': 'Close'
                },
                'intent': {
                    'name': intent_name,
                    'state': 'Fulfilled'
                }
            },
            'messages': [
                {
                    'contentType': 'PlainText',
                    'content': message
                }
            ]
        }

    return {
        'sessionState': {
            'dialogAction': {
                'type': 'Close'
            },
            'intent': {
                'name': intent_name,
                'state': 'Failed'
            }
        }
    }
EOF
    filename = "lambda_function.py"
  }
}

resource "aws_lambda_function" "pizza_ordering" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "pizza_ordering_fulfillment"
  role            = aws_iam_role.lambda_role.arn
  handler         = "lambda_function.lambda_handler"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  runtime         = "python3.11"
  timeout         = 30
}

resource "aws_lambda_permission" "allow_lex" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.pizza_ordering.function_name
  principal     = "lexv2.amazonaws.com"
}

