provider "aws" {
  region = "us-east-1"
}

# IAM Role for Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "pizza_ordering_lex_bot_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexFullAccess"
}

# IAM Role for Lambda Function
resource "aws_iam_role" "lambda_role" {
  name = "pizza_ordering_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Lambda Function
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function.zip"

  source {
    content  = <<EOF
import json

def lambda_handler(event, context):
    intent_name = event['sessionState']['intent']['name']
    slots = event['sessionState']['intent']['slots']

    if intent_name == 'OrderPizza':
        pizza_type = slots.get('PizzaType', {}).get('value', {}).get('interpretedValue')
        pizza_size = slots.get('PizzaSize', {}).get('value', {}).get('interpretedValue')
        quantity = slots.get('Quantity', {}).get('value', {}).get('interpretedValue')

        message = f"Great! I've ordered {quantity} {pizza_size} {pizza_type} pizza(s) for you. Your order will be ready in 30 minutes."

        return {
            'sessionState': {
                'dialogAction': {
                    'type': 'Close'
                },
                'intent': {
                    'name': intent_name,
                    'state': 'Fulfilled'
                }
            },
            'messages': [
                {
                    'contentType': 'PlainText',
                    'content': message
                }
            ]
        }

    return {
        'sessionState': {
            'dialogAction': {
                'type': 'Close'
            },
            'intent': {
                'name': intent_name,
                'state': 'Failed'
            }
        }
    }
EOF
    filename = "lambda_function.py"
  }
}

resource "aws_lambda_function" "pizza_ordering" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "pizza_ordering_fulfillment"
  role            = aws_iam_role.lambda_role.arn
  handler         = "lambda_function.lambda_handler"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  runtime         = "python3.11"
  timeout         = 30
}

resource "aws_lambda_permission" "allow_lex" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.pizza_ordering.function_name
  principal     = "lexv2.amazonaws.com"
}

# Lex V2 Bot
resource "aws_lexv2models_bot" "pizza_ordering_bot" {
  name     = "PizzaOrderingBot"
  role_arn = aws_iam_role.lex_bot_role.arn

  idle_session_ttl_in_seconds = 300

  data_privacy {
    child_directed = false
  }
}

resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id      = aws_lexv2models_bot.pizza_ordering_bot.id
  bot_version = "DRAFT"
  locale_id   = "en_US"
  n_lu_intent_confidence_threshold = 0.40
}

resource "aws_lexv2models_intent" "order_pizza" {
  bot_id      = aws_lexv2models_bot.pizza_ordering_bot.id
  bot_version = "DRAFT"
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "OrderPizza"

  sample_utterance {
    utterance = "I want to order a pizza"
  }

  sample_utterance {
    utterance = "Order pizza"
  }

  sample_utterance {
    utterance = "I'd like to order a {PizzaSize} {PizzaType} pizza"
  }

  sample_utterance {
    utterance = "Can I get {Quantity} pizzas"
  }

  slot_priority {
    priority  = 1
    slot_name = "PizzaType"
  }

  slot_priority {
    priority  = 2
    slot_name = "PizzaSize"
  }

  slot_priority {
    priority  = 3
    slot_name = "Quantity"
  }

  fulfillment_code_hook {
    enabled = true
  }
}

resource "aws_lexv2models_slot" "pizza_type" {
  bot_id      = aws_lexv2models_bot.pizza_ordering_bot.id
  bot_version = "DRAFT"
  intent_id   = aws_lexv2models_intent.order_pizza.id
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "PizzaType"
  slot_type_id = aws_lexv2models_slot_type.pizza_type.slot_type_id

  value_elicitation_setting {
    slot_constraint = "Required"

    prompt_specification {
      max_retries                 = 3
      message_group {
        message {
          plain_text_message {
            value = "What type of pizza would you like? We have Margherita, Pepperoni, Vegetarian, and Hawaiian."
          }
        }
      }
    }
  }
}

resource "aws_lexv2models_slot" "pizza_size" {
  bot_id      = aws_lexv2models_bot.pizza_ordering_bot.id
  bot_version = "DRAFT"
  intent_id   = aws_lexv2models_intent.order_pizza.id
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "PizzaSize"
  slot_type_id = aws_lexv2models_slot_type.pizza_size.slot_type_id

  value_elicitation_setting {
    slot_constraint = "Required"

    prompt_specification {
      max_retries                 = 3
      message_group {
