          plain_text_message {
            value = "What size pizza would you like? Small, Medium, or Large?"
          }
        }
      }
    }
  }
}

resource "aws_lexv2models_slot" "quantity" {
  bot_id      = aws_lexv2models_bot.pizza_ordering_bot.id
  bot_version = "DRAFT"
