# Input Kinesis Stream
resource "aws_kinesis_stream" "input_stream" {
  name             = "kinesis-analytics-input-stream"
  shard_count      = 1
  retention_period = 24

  shard_level_metrics = [
    "IncomingBytes",
    "IncomingRecords",
    "OutgoingBytes",
    "OutgoingRecords"
  ]

  tags = {
    Name = "kinesis-analytics-input-stream"
  }
}

# Kinesis Analytics Application
resource "aws_kinesis_analytics_application" "analytics_app" {
  name = "kinesis-analytics-application"

  code = <<SQL
CREATE OR REPLACE STREAM "DESTINATION_SQL_STREAM" (
  column1 VARCHAR(16),
  column2 INTEGER
);

CREATE OR REPLACE PUMP "STREAM_PUMP" AS 
INSERT INTO "DESTINATION_SQL_STREAM"
SELECT STREAM * 
FROM "SOURCE_SQL_STREAM_001";
SQL

  inputs {
    name_prefix = "SOURCE_SQL_STREAM"

    kinesis_stream {
      resource_arn = aws_kinesis_stream.input_stream.arn
      role_arn     = aws_iam_role.kinesis_analytics_role.arn
    }

    parallelism {
      count = 1
    }

    schema {
      record_columns {
        mapping  = "$.column1"
        name     = "column1"
        sql_type = "VARCHAR(16)"
      }

      record_columns {
        mapping  = "$.column2"
        name     = "column2"
        sql_type = "INTEGER"
      }

      record_encoding = "UTF-8"

      record_format {
        mapping_parameters {
          json {
            record_row_path = "$"
          }
        }
      }
    }
  }

  tags = {
    Name = "kinesis-analytics-application"
  }
}
