# S3 bucket for destination
resource "aws_s3_bucket" "firehose_destination" {
  bucket = "firehose-destination-bucket-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_versioning" "firehose_destination" {
  bucket = aws_s3_bucket.firehose_destination.id
  versioning_configuration {
    status = "Enabled"
  }
}

# S3 bucket for error output
resource "aws_s3_bucket" "firehose_error" {
  bucket = "firehose-error-bucket-${random_id.suffix.hex}"
}

# Random suffix for unique bucket names
resource "random_id" "suffix" {
  byte_length = 8
}

# IAM role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose-delivery-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Firehose
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-delivery-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_destination.arn,
          "${aws_s3_bucket.firehose_destination.arn}/*",
          aws_s3_bucket.firehose_error.arn,
          "${aws_s3_bucket.firehose_error.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents",
          "logs:CreateLogStream"
        ]
        Resource = [
          "${aws_cloudwatch_log_group.firehose_log_group.arn}:*"
        ]
      }
    ]
  })
}

# CloudWatch Log Group
resource "aws_cloudwatch_log_group" "firehose_log_group" {
  name              = "/aws/kinesisfirehose/delivery-stream"
  retention_in_days = 7
}

# CloudWatch Log Stream
resource "aws_cloudwatch_log_stream" "firehose_log_stream" {
  name           = "S3Delivery"
  log_group_name = aws_cloudwatch_log_group.firehose_log_group.name
}

# Kinesis Firehose Delivery Stream with Dynamic Partitioning
resource "aws_kinesis_firehose_delivery_stream" "extended_s3_stream" {
  name        = "terraform-kinesis-firehose-extended-s3-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_destination.arn

    # Dynamic Partitioning Configuration
    dynamic_partitioning_configuration {
      enabled = true
    }

    # Prefix with dynamic partitioning keys
    prefix              = "data/year=!{partitionKeyFromQuery:year}/month=!{partitionKeyFromQuery:month}/day=!{partitionKeyFromQuery:day}/hour=!{partitionKeyFromQuery:hour}/"
    error_output_prefix = "errors/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/hour=!{timestamp:HH}/!{firehose:error-output-type}/"

    buffering_size     = 128
    buffering_interval = 300

    compression_format = "GZIP"

    # Processing Configuration for Dynamic Partitioning
    processing_configuration {
      enabled = true

      processors {
        type = "MetadataExtraction"
        parameters {
          parameter_name  = "MetadataExtractionQuery"
          parameter_value = "{year:.timestamp|strftime("%Y"),month:.timestamp|strftime("%m"),day:.timestamp|strftime("%d"),hour:.timestamp|strftime("%H")}"
        }
        parameters {
          parameter_name  = "JsonParsingEngine"
          parameter_value = "JQ-1.6"
        }
      }

      processors {
        type = "AppendDelimiterToRecord"
        parameters {
          parameter_name  = "Delimiter"
          parameter_value = "\n"
        }
      }
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose_log_group.name
      log_stream_name = aws_cloudwatch_log_stream.firehose_log_stream.name
    }

    s3_backup_mode = "Disabled"
  }
}

output "firehose_delivery_stream_name" {
  value       = aws_kinesis_firehose_delivery_stream.extended_s3_stream.name
  description = "Name of the Kinesis Firehose Delivery Stream"
}

output "firehose_delivery_stream_arn" {
  value       = aws_kinesis_firehose_delivery_stream.extended_s3_stream.arn
  description = "ARN of the Kinesis Firehose Delivery Stream"
}

output "destination_bucket_name" {
  value       = aws_s3_bucket.firehose_destination.id
  description = "Name of the destination S3 bucket"
}

