provider "aws" {
  region = "us-east-1"
}

# IAM role for Kinesis Firehose
resource "aws_iam_role" "firehose_role" {
  name = "kinesis-firehose-splunk-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# S3 bucket for failed events and backup
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "kinesis-firehose-splunk-backup-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_versioning" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.id
  versioning_configuration {
    status = "Enabled"
  }
}

# IAM policy for Firehose to access S3
resource "aws_iam_role_policy" "firehose_s3_policy" {
  name = "kinesis-firehose-s3-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      }
    ]
  })
}

