terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC Configuration
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "firehose-vpc"
  }
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "firehose-private-subnet-${count.index + 1}"
  }
}

resource "aws_security_group" "elasticsearch" {
  name_description = "Security group for Elasticsearch access from Firehose"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "firehose-elasticsearch-sg"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# S3 Bucket for backup
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-elasticsearch-backup-${random_id.bucket_suffix.hex}"

  tags = {
    Name = "firehose-backup-bucket"
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_s3_bucket_public_access_block" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Elasticsearch Domain
resource "aws_elasticsearch_domain" "main" {
  domain_name           = "firehose-es-domain"
  elasticsearch_version = "7.10"

  cluster_config {
    instance_type  = "t3.small.elasticsearch"
    instance_count = 2
    zone_awareness_enabled = true

    zone_awareness_config {
      availability_zone_count = 2
    }
  }

  vpc_options {
    subnet_ids         = aws_subnet.private[*].id
    security_group_ids = [aws_security_group.elasticsearch.id]
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
    volume_type = "gp2"
  }

  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action   = "es:*"
        Resource = "arn:aws:es:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:domain/firehose-es-domain/*"
      }
    ]
  })

  tags = {
    Name = "firehose-elasticsearch"
  }
}

data "aws_region" "current" {}
data "aws_caller_identity" "current" {}

# IAM Role for Firehose
resource "aws_iam_role" "firehose" {
  name = "firehose-elasticsearch-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose" {
  name = "firehose-elasticsearch-policy"
  role = aws_iam_role.firehose.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:DescribeElasticsearchDomain",
          "es:DescribeElasticsearchDomains",
          "es:DescribeElasticsearchDomainConfig",
          "es:ESHttpPost",
          "es:ESHttpPut"
        ]
        Resource = [
          aws_elasticsearch_domain.main.arn,
          "${aws_elasticsearch_domain.main.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:ESHttpGet"
        ]
        Resource = [
          "${aws_elasticsearch_domain.main.arn}/_all/_settings",
          "${aws_elasticsearch_domain.main.arn}/_cluster/stats",
          "${aws_elasticsearch_domain.main.arn}/index-name*/_mapping/type-name",
          "${aws_elasticsearch_domain.main.arn}/_nodes",
          "${aws_elasticsearch_domain.main.arn}/_nodes/stats",
          "${aws_elasticsearch_domain.main.arn}/_nodes/*/stats",
          "${aws_elasticsearch_domain.main.arn}/_stats",
          "${aws_elasticsearch_domain.main.arn}/index-name*/_stats"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = [
          aws_cloudwatch_log_group.firehose.arn,
          "${aws_cloudwatch_log_group.firehose.arn}:*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:DescribeVpcs",
          "ec2:DescribeVpcAttribute",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeNetworkInterfaces",
          "ec2:CreateNetworkInterface",
          "ec2:CreateNetworkInterfacePermission",
          "ec2:DeleteNetworkInterface"
        ]
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Log Group
resource "aws_cloudwatch_log_group" "firehose" {
  name              = "/aws/kinesisfirehose/firehose-elasticsearch-delivery"
  retention_in_days = 7

  tags = {
    Name = "firehose-elasticsearch-logs"
  }
}

resource "aws_cloudwatch_log_stream" "firehose_elasticsearch" {
  name           = "ElasticsearchDelivery"
  log_group_name = aws_cloudwatch_log_group.firehose.name
}

resource "aws_cloudwatch_log_stream" "firehose_s3" {
  name           = "S3Delivery"
  log_group_name = aws_cloudwatch_log_group.firehose.name
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "elasticsearch" {
  name        = "firehose-elasticsearch-delivery-stream"
  destination = "elasticsearch"

  elasticsearch_configuration {
    domain_arn = aws_elasticsearch_domain.main.arn
    role_arn   = aws_iam_role.firehose.arn
    index_name = "firehose-index"
    type_name  = "_doc"

    index_rotation_period = "OneDay"
    buffering_interval    = 300
    buffering_size        = 5

    retry_duration = 300

    s3_backup_mode = "AllDocuments"

    s3_configuration {
      role_arn           = aws_iam_role.firehose.arn
      bucket_arn         = aws_s3_bucket.firehose_backup.arn
      buffering_size     = 5
      buffering_interval = 300
      compression_format = "GZIP"

      cloudwatch_logging_options {
        enabled         = true
        log_group_name  = aws_cloudwatch_log_group.firehose.name
        log_stream_name = aws_cloudwatch_log_stream.firehose_s3.name
      }
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose.name
      log_stream_name = aws_cloudwatch_log_stream.firehose_elasticsearch.name
    }

    vpc_config {
      subnet_ids         = aws_subnet.private[*].id
      security_group_ids = [aws_security_group.elasticsearch.id]
      role_arn           = aws_iam_role.firehose.arn
    }
  }

  tags = {
    Name = "firehose-elasticsearch-stream"
  }
}

output "firehose_stream_name" {
  description = "Name of the Kinesis Firehose Delivery Stream"
  value       = aws_kinesis_firehose_delivery_stream.elasticsearch.name
}

output "firehose_stream_arn" {
  description = "ARN of the Kinesis Firehose Delivery Stream"
  value       = aws_kinesis_firehose_delivery_stream.elasticsearch.arn
}

output "elasticsearch_endpoint" {
  description = "Endpoint of the Elasticsearch domain"
  value       = aws_elasticsearch_domain.main.endpoint
}

output "elasticsearch_vpc_endpoint" {
  description = "VPC endpoint of the Elasticsearch domain"
  value       = aws_elasticsearch_domain.main.vpc_options[0].vpc_id
}

output "s3_backup_bucket" {
  description = "S3 bucket for Firehose backup"
  value       = aws_s3_bucket.firehose_backup.id
}

