        ]
      }
    ]
  })
}

# S3 bucket for failed/backup data
resource "aws_s3_bucket" "backup_bucket" {
  bucket = "kinesis-firehose-http-backup-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_versioning" "backup_bucket_versioning" {
  bucket = aws_s3_bucket.backup_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# CloudWatch Log Group for Firehose logs
resource "aws_cloudwatch_log_group" "firehose_log_group" {
  name              = "/aws/kinesisfirehose/http-endpoint-delivery-stream"
  retention_in_days = 7
}

resource "aws_cloudwatch_log_stream" "firehose_log_stream" {
  name           = "HttpEndpointDelivery"
  log_group_name = aws_cloudwatch_log_group.firehose_log_group.name
}

# Kinesis Firehose Delivery Stream with HTTP Endpoint
resource "aws_kinesis_firehose_delivery_stream" "http_endpoint_stream" {
  name        = "http-endpoint-delivery-stream"
  destination = "http_endpoint"

  http_endpoint_configuration {
    url                = "https://aws-api.newrelic.com/firehose/v1"
    name               = "New Relic"
    access_key         = var.newrelic_license_key
    buffering_size     = 5
    buffering_interval = 300
    role_arn           = aws_iam_role.firehose_role.arn
    s3_backup_mode     = "FailedDataOnly"

    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.backup_bucket.arn
      buffering_size     = 5
      buffering_interval = 300
      compression_format = "GZIP"
      prefix             = "failed-data/"
      error_output_prefix = "error/"

      cloudwatch_logging_options {
        enabled         = true
        log_group_name  = aws_cloudwatch_log_group.firehose_log_group.name
        log_stream_name = aws_cloudwatch_log_stream.firehose_log_stream.name
      }
    }

    request_configuration {
      content_encoding = "GZIP"

      common_attributes {
        name  = "environment"
        value = "production"
      }
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose_log_group.name
      log_stream_name = aws_cloudwatch_log_stream.firehose_log_stream.name
    }

    retry_duration = 300
  }
}

# Data source for current AWS account ID
data "aws_caller_identity" "current" {}

# Variables
variable "newrelic_license_key" {
  description = "New Relic License Key for HTTP endpoint authentication"
  type        = string
  sensitive   = true
}

# Outputs
output "firehose_stream_name" {
  description = "Name of the Kinesis Firehose Delivery Stream"
  value       = aws_kinesis_firehose_delivery_stream.http_endpoint_stream.name
}

output "firehose_stream_arn" {
  description = "ARN of the Kinesis Firehose Delivery Stream"
  value       = aws_kinesis_firehose_delivery_stream.http_endpoint_stream.arn
}

output "backup_bucket_name" {
  description = "Name of the S3 backup bucket"
  value       = aws_s3_bucket.backup_bucket.id
}

