```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC Configuration
resource "aws_vpc" "opensearch_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "opensearch-vpc"
  }
}

resource "aws_subnet" "opensearch_subnet_1" {
  vpc_id            = aws_vpc.opensearch_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "opensearch-subnet-1"
  }
}

resource "aws_subnet" "opensearch_subnet_2" {
  vpc_id            = aws_vpc.opensearch_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "opensearch-subnet-2"
  }
}

resource "aws_security_group" "opensearch_sg" {
  name        = "opensearch-security-group"
  description = "Security group for OpenSearch domain"
  vpc_id      = aws_vpc.opensearch_vpc.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.opensearch_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "opensearch-sg"
  }
}

# OpenSearch Domain
resource "aws_opensearch_domain" "opensearch_domain" {
  domain_name    = "firehose-opensearch-domain"
  engine_version = "OpenSearch_2.11"

  cluster_config {
    instance_type          = "t3.small.search"
    instance_count         = 2
    zone_awareness_enabled = true

    zone_awareness_config {
      availability_zone_count = 2
    }
  }

  vpc_options {
    subnet_ids = [
      aws_subnet.opensearch_subnet_1.id,
      aws_subnet.opensearch_subnet_2.id
    ]
    security_group_ids = [aws_security_group.opensearch_sg.id]
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
    volume_type = "gp3"
  }

  encrypt_at_rest {
    enabled = true
  }

  node_to_node_encryption {
    enabled = true
  }

  domain_endpoint_options {
    enforce_https       = true
    tls_security_policy = "Policy-Min-TLS-1-2-2019-07"
  }

  advanced_security_options {
    enabled                        = true
    internal_user_database_enabled = true
    master_user_options {
      master_user_name     = "admin"
      master_user_password = "Admin123!"
    }
  }

  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action   = "es:*"
        Resource = "arn:aws:es:us-east-1:*:domain/firehose-opensearch-domain/*"
      }
    ]
  })

  tags = {
    Name = "firehose-opensearch-domain"
  }
}

# S3 Bucket for Backup
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-opensearch-backup-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name = "firehose-backup-bucket"
  }
}

resource "aws_s3_bucket_versioning" "firehose_backup_versioning" {
  bucket = aws_s3_bucket.firehose_backup.id

  versioning_configuration {
    status = "Enabled"
  }
}

# IAM Role for Kinesis Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose-opensearch-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "firehose-opensearch-role"
  }
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-opensearch-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:DescribeElasticsearchDomain",
          "es:DescribeElasticsearchDomains",
          "es:DescribeElasticsearchDomainConfig",
          "es:ESHttpPost",
          "es:ESHttpPut"
        ]
        Resource = [
          aws_opensearch_domain.opensearch_domain.arn,
          "${aws_opensearch_domain.opensearch_domain.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:ESHttpGet"
        ]
        Resource = [
          "${aws_opensearch_domain.opensearch_domain.arn}/_all/_settings",
          "${aws_opensearch_domain.opensearch_domain.arn}/_cluster/stats",
          "${aws_opensearch_domain.opensearch_domain.arn}/myindex*/_mapping/mytype",
          "${aws_opensearch_domain.opensearch_domain.arn}/_nodes",
          "${aws_opensearch_domain.opensearch_domain.arn}/_nodes/stats",
          "${aws_opensearch_domain.opensearch_domain.arn}/_nodes/*/stats",
          "${aws_opensearch_domain.opensearch_domain.arn}/_stats",
          "${aws_opensearch_domain.opensearch_domain.arn}/myindex*/_stats"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents",
          "logs:CreateLogStream"
        ]
        Resource = [
          "arn:aws:logs:us-east-1:*:log-group:/aws/kinesisfirehose/*:log-stream:*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:DescribeVpcs",
          "ec2:DescribeVpcAttribute",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeNetworkInterfaces",
          "ec2:CreateNetworkInterface",
          "ec2:CreateNetworkInterfacePermission",
          "ec2:DeleteNetworkInterface"
        ]
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Log Group for Firehose
resource "aws_cloudwatch_log_group" "firehose_log_group" {
  name              = "/aws/kinesisfirehose/opensearch-delivery-stream"
  retention_in_days = 7

  tags = {
    Name = "firehose-opensearch-logs"
  }
}

resource "aws_cloudwatch_log_stream" "firehose_log_stream" {
  name           = "opensearch-delivery"
  log_group_name = aws_cloudwatch_log_group.firehose_log_group.name
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "opensearch_stream" {
  name        = "opensearch-delivery-stream"
  destination = "opensearch"

  opensearch_configuration {
    domain_arn = aws_opensearch_domain.opensearch_domain.arn
    role_arn   = aws_iam_role.firehose_role.arn
    index_name = "firehose-index"

    index_rotation_period = "OneDay"

    buffering_interval = 300
    buffering_size     = 5

    retry_duration = 300

    s3_backup_mode = "AllDocuments"

    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_backup.arn
      buffering_size     = 5
      buffering_interval = 300
      compression_format = "GZIP"

      cloudwatch_logging_options {
        enabled         = true
        log_group_name  = aws_cloudwatch_log_group.firehose_log_group.name
        log_stream_name = aws_cloudwatch_log_stream.firehose_log_stream.name
      }
    }

    vpc_config {
      subnet_ids         = [aws_subnet.opensearch_subnet_1.id, aws_subnet.opensearch_subnet_2.id]
      security_group_ids = [aws_security_group.opensearch_sg.id]
      role_arn           = aws_iam_role.firehose_role.arn
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose_log_group.name
      log_stream_name = aws_cloudwatch_log_stream.firehose_log_stream.name
    }
  }

  tags = {
    Name = "opensearch-delivery-stream"
  }

  depends_on = [
    aws_iam_role_policy.firehose_policy
  ]
}

# Data source for current AWS account
data "aws_caller_identity" "current" {}

# Outputs
output "firehose_stream_name" {
  description = "Name of the Kinesis Firehose delivery stream"
  value       = aws_kinesis_firehose_delivery_stream.opensearch_stream.name
}

output "firehose_stream_arn" {
  description = "ARN of the Kinesis Firehose delivery stream"
  value       = aws_kinesis_firehose_delivery_stream.opensearch_stream.arn
}

output "opensearch_endpoint" {
  description = "Endpoint of the OpenSearch domain"
  value       = aws_opensearch_domain.opensearch_domain.endpoint
}

output "opensearch_domain_id" {
  description = "ID of the OpenSearch domain"
  value       = aws_opensearch_domain.opensearch_domain.domain_id
}

output "backup_bucket_name" {
  description = "Name of the S3 backup bucket"
  value       = aws_s3_bucket.firehose_backup.id
}
```

