provider "aws" {
  region = "us-east-1"
}

# IAM role for Kendra index
resource "aws_iam_role" "kendra_index_role" {
  name = "kendra-index-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "kendra_index_policy" {
  name = "kendra-index-policy"
  role = aws_iam_role.kendra_index_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "cloudwatch:PutMetricData"
        ]
        Resource = "*"
        Condition = {
          StringEquals = {
            "cloudwatch:namespace" = "AWS/Kendra"
          }
        }
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:log-group:/aws/kendra/*"
      }
    ]
  })
}

# IAM role for Kendra data source
resource "aws_iam_role" "kendra_datasource_role" {
  name = "kendra-datasource-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "kendra_datasource_policy" {
  name = "kendra-datasource-policy"
  role = aws_iam_role.kendra_datasource_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          "${aws_s3_bucket.kendra_bucket.arn}",
          "${aws_s3_bucket.kendra_bucket.arn}/*"
        ]
      }
    ]
  })
}

# S3 bucket for Kendra documents
resource "aws_s3_bucket" "kendra_bucket" {
  bucket = "kendra-documents-bucket-${data.aws_caller_identity.current.account_id}"
}

# Kendra index
resource "aws_kendra_index" "example" {
  name        = "example-kendra-index"
  description = "Example Kendra index"
  edition     = "DEVELOPER_EDITION"
  role_arn    = aws_iam_role.kendra_index_role.arn

  server_side_encryption_configuration {
    kms_key_id = aws_kms_key.kendra_key.arn
  }
}

# KMS key for encryption
resource "aws_kms_key" "kendra_key" {
  description = "KMS key for Kendra encryption"
}

# Kendra data source with proxy configuration
resource "aws_kendra_data_source" "example" {
  index_id = aws_kendra_index.example.id
  name     = "example-s3-datasource"
  type     = "WEBCRAWLER"
  role_arn = aws_iam_role.kendra_datasource_role.arn

  configuration {
    web_crawler_configuration {
      urls {
        seed_url_configuration {
          seed_urls = [
            "https://example.com"
          ]
        }
      }

      proxy_configuration {
        host = "proxy.example.com"
        port = 8080
        credentials = aws_secretsmanager_secret.proxy_credentials.arn
      }

      crawl_depth                     = 2
      max_links_per_page              = 100
      max_content_size_per_page_in_mega_bytes = 50
      max_urls_per_minute_crawl_rate  = 300
    }
  }

  schedule = "cron(0 12 * * ? *)"
}

# Secret for proxy credentials
resource "aws_secretsmanager_secret" "proxy_credentials" {
  name = "kendra-proxy-credentials"
}

resource "aws_secretsmanager_secret_version" "proxy_credentials" {
  secret_id = aws_secretsmanager_secret.proxy_credentials.id
  secret_string = jsonencode({
    username = "proxy-user"
    password = "proxy-password"
  })
}

# Grant Kendra access to the secret
resource "aws_iam_role_policy" "kendra_secrets_policy" {
  name = "kendra-secrets-policy"
  role = aws_iam_role.kendra_datasource_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue"
        ]
        Resource = aws_secretsmanager_secret.proxy_credentials.arn
      }
    ]
  })
}

data "aws_caller_identity" "current" {}

