provider "aws" {
  region = "us-east-1"
}

# IAM Role for Kendra Index
resource "aws_iam_role" "kendra_index_role" {
  name = "kendra-index-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "kendra_index_policy" {
  name = "kendra-index-policy"
  role = aws_iam_role.kendra_index_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "cloudwatch:PutMetricData"
        ]
        Resource = "*"
        Condition = {
          StringEquals = {
            "cloudwatch:namespace" = "AWS/Kendra"
          }
        }
      },
      {
        Effect = "Allow"
        Action = [
          "logs:DescribeLogGroups"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup"
        ]
        Resource = "arn:aws:logs:*:*:log-group:/aws/kendra/*"
      },
      {
        Effect = "Allow"
        Action = [
          "logs:DescribeLogStreams",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:log-group:/aws/kendra/*:log-stream:*"
      }
    ]
  })
}

# Kendra Index
resource "aws_kendra_index" "example" {
  name     = "example-kendra-index"
  role_arn = aws_iam_role.kendra_index_role.arn

  server_side_encryption_configuration {
    kms_key_id = null
  }
}

# IAM Role for Kendra Data Source
resource "aws_iam_role" "kendra_data_source_role" {
  name = "kendra-data-source-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "kendra_data_source_policy" {
  name = "kendra-data-source-policy"
  role = aws_iam_role.kendra_data_source_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kendra:BatchPutDocument",
          "kendra:BatchDeleteDocument"
        ]
        Resource = aws_kendra_index.example.arn
      }
    ]
  })
}

# Kendra Data Source with URL Inclusion and Exclusion Patterns
resource "aws_kendra_data_source" "example" {
  index_id = aws_kendra_index.example.id
  name     = "example-web-crawler-data-source"
  type     = "WEBCRAWLER"
  role_arn = aws_iam_role.kendra_data_source_role.arn

  configuration {
    web_crawler_configuration {
      urls {
        seed_url_configuration {
          seed_urls = [
            "https://example.com",
            "https://docs.example.com"
          ]
        }
      }

      url_inclusion_patterns = [
        ".*https://example\.com/docs/.*",
        ".*https://example\.com/blog/.*",
        ".*\.html$",
        ".*\.pdf$"
      ]

      url_exclusion_patterns = [
        ".*https://example\.com/private/.*",
        ".*https://example\.com/admin/.*",
        ".*https://example\.com/login.*",
        ".*\.jpg$",
        ".*\.png$",
        ".*\.css$",
        ".*\.js$"
      ]

      crawl_depth                 = 3
      max_links_per_page          = 100
      max_urls_per_minute_crawl_rate = 300
    }
  }

  schedule = "cron(0 0 * * ? *)"
}

output "kendra_index_id" {
  value       = aws_kendra_index.example.id
  description = "The ID of the Kendra Index"
}

output "kendra_data_source_id" {
  value       = aws_kendra_data_source.example.id
  description = "The ID of the Kendra Data Source"
}

output "kendra_data_source_arn" {
  value       = aws_kendra_data_source.example.arn
  description = "The ARN of the Kendra Data Source"
}
