      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM role for Kendra
resource "aws_iam_role" "kendra_role" {
  name = "kendra-index-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Kendra
resource "aws_iam_role_policy" "kendra_policy" {
  name = "kendra-index-policy"
  role = aws_iam_role.kendra_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "cloudwatch:PutMetricData"
        ]
        Resource = "*"
        Condition = {
          StringEquals = {
            "cloudwatch:namespace" = "AWS/Kendra"
          }
        }
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:log-group:/aws/kendra/*"
      }
    ]
  })
}

# Kendra index with user group resolution configuration
resource "aws_kendra_index" "main" {
  name        = "kendra-index-with-user-groups"
  description = "Kendra index with user group resolution configuration"
  edition     = "DEVELOPER_EDITION"
  role_arn    = aws_iam_role.kendra_role.arn

  user_group_resolution_configuration {
    user_group_resolution_mode = "AWS_SSO"
  }

  user_token_configurations {
    json_token_type_configuration {
      group_attribute_field = "groups"
      user_name_attribute_field = "username"
    }
  }

  tags = {
    Name        = "kendra-index"
    Environment = "development"
  }
}

output "kendra_index_id" {
  description = "The ID of the Kendra index"
  value       = aws_kendra_index.main.id
}

output "kendra_index_arn" {
  description = "The ARN of the Kendra index"
  value       = aws_kendra_index.main.arn
}
```

