terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

provider "aws" {
  alias  = "eu-central-1"
  region = "eu-central-1"
}

# Route 53 Hosted Zone
resource "aws_route53_zone" "primary" {
  name = "primary.example.com"
}

# VPC for us-east-1
resource "aws_vpc" "us_east_1" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "vpc-us-east-1"
  }
}

# Subnet for us-east-1
resource "aws_subnet" "us_east_1" {
  vpc_id                  = aws_vpc.us_east_1.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-us-east-1"
  }
}

# Internet Gateway for us-east-1
resource "aws_internet_gateway" "us_east_1" {
  vpc_id = aws_vpc.us_east_1.id

  tags = {
    Name = "igw-us-east-1"
  }
}

# Route Table for us-east-1
resource "aws_route_table" "us_east_1" {
  vpc_id = aws_vpc.us_east_1.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.us_east_1.id
  }

  tags = {
    Name = "rt-us-east-1"
  }
}

resource "aws_route_table_association" "us_east_1" {
  subnet_id      = aws_subnet.us_east_1.id
  route_table_id = aws_route_table.us_east_1.id
}

# Security Group for us-east-1
resource "aws_security_group" "us_east_1" {
  name        = "allow-http-us-east-1"
  description = "Allow HTTP inbound traffic"
  vpc_id      = aws_vpc.us_east_1.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# EC2 Instance for us-east-1
resource "aws_instance" "us_east_1" {
  ami                    = "ami-0c55b159cbfafe1f0" # Amazon Linux 2 AMI (update as needed)
  instance_type          = "t2.micro"
  subnet_id              = aws_subnet.us_east_1.id
  vpc_security_group_ids = [aws_security_group.us_east_1.id]

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "US East 1 Server" > /var/www/html/index.html
              EOF

  tags = {
    Name = "web-server-us-east-1"
  }
}

# VPC for eu-central-1
resource "aws_vpc" "eu_central_1" {
  provider             = aws.eu-central-1
  cidr_block           = "10.1.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "vpc-eu-central-1"
  }
}

# Subnet for eu-central-1
resource "aws_subnet" "eu_central_1" {
  provider                = aws.eu-central-1
  vpc_id                  = aws_vpc.eu_central_1.id
  cidr_block              = "10.1.1.0/24"
  availability_zone       = "eu-central-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-eu-central-1"
  }
}

# Internet Gateway for eu-central-1
resource "aws_internet_gateway" "eu_central_1" {
  provider = aws.eu-central-1
  vpc_id   = aws_vpc.eu_central_1.id

  tags = {
    Name = "igw-eu-central-1"
  }
}

# Route Table for eu-central-1
resource "aws_route_table" "eu_central_1" {
  provider = aws.eu-central-1
  vpc_id   = aws_vpc.eu_central_1.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.eu_central_1.id
  }

  tags = {
    Name = "rt-eu-central-1"
  }
}

resource "aws_route_table_association" "eu_central_1" {
  provider       = aws.eu-central-1
  subnet_id      = aws_subnet.eu_central_1.id
