        }
        Secondary = {
          RuleType = "weighted"
          Items = [
            {
              EndpointReference = "secondary_endpoint"
              Weight            = 70
            },
            {
              EndpointReference = "tertiary_endpoint"
              Weight            = 30
            }
          ]
        }
      }
    }
    StartRule = "main_rule"
  })
}

# Health Check for Primary Endpoint
resource "aws_route53_health_check" "primary" {
  ip_address        = "192.0.2.1"
  port              = 80
  type              = "HTTP"
  resource_path     = "/health"
  failure_threshold = 3
  request_interval  = 30

  tags = {
    Name = "Primary Endpoint Health Check"
  }
}

# Route 53 Traffic Policy Instance
resource "aws_route53_traffic_policy_instance" "main" {
  name                   = "www.example.com"
  traffic_policy_id      = aws_route53_traffic_policy.main.id
  traffic_policy_version = aws_route53_traffic_policy.main.version
  hosted_zone_id         = aws_route53_zone.main.zone_id
  ttl                    = 300
}

# Outputs
output "hosted_zone_id" {
  description = "The hosted zone ID"
  value       = aws_route53_zone.main.zone_id
}

output "traffic_policy_id" {
  description = "The traffic policy ID"
  value       = aws_route53_traffic_policy.main.id
}

output "traffic_policy_version" {
  description = "The traffic policy version"
  value       = aws_route53_traffic_policy.main.version
}

output "traffic_policy_instance_id" {
  description = "The traffic policy instance ID"
  value       = aws_route53_traffic_policy_instance.main.id
}
