terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    kubernetes = {
      source  = "hashicorp/kubernetes"
      version = "~> 2.0"
    }
    null = {
      source  = "hashicorp/null"
      version = "~> 3.0"
    }
  }
}

# Data source for EKS cluster (assuming it exists)
data "aws_eks_cluster" "cluster" {
  name = var.cluster_name
}

data "aws_eks_cluster_auth" "cluster" {
  name = var.cluster_name
}

# IAM role for EKS Fargate profile
resource "aws_iam_role" "fargate_pod_execution_role" {
  name = "${var.cluster_name}-fargate-pod-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "eks-fargate-pods.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })

  tags = {
    Name = "${var.cluster_name}-fargate-pod-execution-role"
  }
}

# Attach AmazonEKSFargatePodExecutionRolePolicy to the IAM role
resource "aws_iam_role_policy_attachment" "fargate_pod_execution_role_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSFargatePodExecutionRolePolicy"
  role       = aws_iam_role.fargate_pod_execution_role.name
}

# EKS Fargate profile for kube-system namespace
resource "aws_eks_fargate_profile" "kube_system" {
  cluster_name           = var.cluster_name
  fargate_profile_name   = "kube-system-fargate-profile"
  pod_execution_role_arn = aws_iam_role.fargate_pod_execution_role.arn
  subnet_ids             = var.subnet_ids

  selector {
    namespace = "kube-system"
  }

  tags = {
    Name = "kube-system-fargate-profile"
  }

  depends_on = [
    aws_iam_role_policy_attachment.fargate_pod_execution_role_policy
  ]
}

# Kubernetes provider configuration
provider "kubernetes" {
  host                   = data.aws_eks_cluster.cluster.endpoint
  cluster_ca_certificate = base64decode(data.aws_eks_cluster.cluster.certificate_authority[0].data)
  token                  = data.aws_eks_cluster_auth.cluster.token
}

# Null resource to patch CoreDNS deployment
resource "null_resource" "patch_coredns" {
  provisioner "local-exec" {
    command = <<-EOT
      kubectl patch deployment coredns \n        --namespace kube-system \n        --type json \n        -p='[{"op": "remove", "path": "/spec/template/metadata/annotations/eks.amazonaws.com~1compute-type"}]' \n        --server='${data.aws_eks_cluster.cluster.endpoint}' \n        --certificate-authority=<(echo '${data.aws_eks_cluster.cluster.certificate_authority[0].data}' | base64 -d) \n        --token='${data.aws_eks_cluster_auth.cluster.token}'
    EOT

    interpreter = ["/bin/bash", "-c"]
  }

  depends_on = [
    aws_eks_fargate_profile.kube_system
  ]
}

# Variables
variable "cluster_name" {
  description = "Name of the EKS cluster"
  type        = string
}

variable "subnet_ids" {
  description = "List of subnet IDs for the Fargate profile (must have tag kubernetes.io/cluster/<cluster-name> = shared/owned)"
  type        = list(string)
}

# Outputs
output "fargate_pod_execution_role_arn" {
  description = "ARN of the Fargate pod execution role"
  value       = aws_iam_role.fargate_pod_execution_role.arn
}

output "fargate_profile_id" {
  description = "ID of the Fargate profile"
  value       = aws_eks_fargate_profile.kube_system.id
}

output "fargate_profile_status" {
  description = "Status of the Fargate profile"
  value       = aws_eks_fargate_profile.kube_system.status
}

