variable "bucket_suffix" {
  description = "Suffix for bucket names"
  type        = string
  default     = "test"
}

# CloudGoat Data Storage Bucket
resource "aws_s3_bucket" "cloudgoat_data" {
  bucket = "cloudgoat-data-${var.bucket_suffix}"
}

resource "aws_s3_bucket_acl" "cloudgoat_data_acl" {
  bucket = aws_s3_bucket.cloudgoat_data.id
  acl    = "private"
}

resource "aws_s3_bucket_ownership_controls" "cloudgoat_data_ownership" {
  bucket = aws_s3_bucket.cloudgoat_data.id

  rule {
    object_ownership = "ObjectWriter"
  }
}

# Web Data Storage Bucket
resource "aws_s3_bucket" "web_data" {
  bucket = "web-data-${var.bucket_suffix}"
}

# Upload object to web data bucket
resource "aws_s3_object" "order_data" {
  bucket = aws_s3_bucket.web_data.id
  key    = "order_data2.csv"
  source = "order_data2.csv"
  etag   = filemd5("order_data2.csv")
}

# Public Access Block for web data bucket
resource "aws_s3_bucket_public_access_block" "web_data_public_access" {
  bucket = aws_s3_bucket.web_data.id

  ignore_public_acls      = true
  block_public_acls       = true
  restrict_public_buckets = true
  block_public_policy     = false
}

# Bucket Policy for web data bucket
resource "aws_s3_bucket_policy" "web_data_policy" {
  bucket = aws_s3_bucket.web_data.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowPutObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:PutObject"
        Resource  = "${aws_s3_bucket.web_data.arn}/*"
      }
    ]
  })

  depends_on = [aws_s3_bucket_public_access_block.web_data_public_access]
}

