}

provider "aws" {
  region = "us-east-1"
}

# VPC for the Memcached cluster
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "memcached-vpc"
  }
}

# Subnets
resource "aws_subnet" "subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "memcached-subnet-1"
  }
}

resource "aws_subnet" "subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "memcached-subnet-2"
  }
}

# Subnet group for ElastiCache
resource "aws_elasticache_subnet_group" "memcached" {
  name       = "memcached-subnet-group"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "memcached-subnet-group"
  }
}

# Security group for Memcached
resource "aws_security_group" "memcached" {
  name        = "memcached-sg"
  description = "Security group for Memcached cluster"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 11211
    to_port     = 11211
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
    description = "Memcached port"
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Allow all outbound traffic"
  }

  tags = {
    Name = "memcached-sg"
  }
}

# ElastiCache Memcached Cluster
resource "aws_elasticache_cluster" "memcached" {
  cluster_id           = "memcached-cluster"
  engine               = "memcached"
  node_type            = "cache.t3.micro"
  num_cache_nodes      = 2
  parameter_group_name = "default.memcached1.6"
  port                 = 11211
  subnet_group_name    = aws_elasticache_subnet_group.memcached.name
  security_group_ids   = [aws_security_group.memcached.id]
  az_mode              = "cross-az"
  preferred_availability_zones = [
    "us-east-1a",
    "us-east-1b"
  ]

  tags = {
    Name        = "memcached-cluster"
    Environment = "production"
  }
}

# Outputs
output "memcached_cluster_id" {
  description = "The cluster ID"
  value       = aws_elasticache_cluster.memcached.cluster_id
}

output "memcached_configuration_endpoint" {
  description = "The configuration endpoint"
  value       = aws_elasticache_cluster.memcached.configuration_endpoint
}

output "memcached_cluster_address" {
  description = "The DNS name of the cache cluster without the port appended"
  value       = aws_elasticache_cluster.memcached.cluster_address
}

output "memcached_cache_nodes" {
  description = "List of cache nodes"
  value       = aws_elasticache_cluster.memcached.cache_nodes
}
