  automated_snapshot_retention_period = 7
  preferred_maintenance_window        = "sun:05:00-sun:06:00"

  # Skip final snapshot on destroy for easier cleanup
  skip_final_snapshot = true

  # Publicly accessible (set to false for production)
  publicly_accessible = false

  # Enhanced VPC routing
  enhanced_vpc_routing = false
}

# EventBridge rule to trigger snapshot creation every 12 hours
resource "aws_cloudwatch_event_rule" "redshift_snapshot_schedule" {
  name                = "redshift-snapshot-every-12-hours"
  description         = "Trigger Redshift snapshot creation every 12 hours"
  schedule_expression = "rate(12 hours)"
}

resource "aws_cloudwatch_event_target" "redshift_snapshot" {
