resource "aws_redshift_snapshot_copy_grant" "primary" {
  provider = aws.primary

  snapshot_copy_grant_name = "redshift-copy-grant"
}

# Configure snapshot copy to us-east-2
resource "aws_redshift_cluster" "primary_with_snapshot_copy" {
  provider = aws.primary

  cluster_identifier  = aws_redshift_cluster.primary.cluster_identifier
  database_name      = aws_redshift_cluster.primary.database_name
