  cluster_type       = aws_redshift_cluster.primary.cluster_type
  number_of_nodes    = aws_redshift_cluster.primary.number_of_nodes

  publicly_accessible = aws_redshift_cluster.primary.publicly_accessible
  encrypted          = aws_redshift_cluster.primary.encrypted

  skip_final_snapshot = true

  snapshot_copy {
    destination_region = "us-east-2"
    retention_period   = 7
    grant_name        = aws_redshift_snapshot_copy_grant.primary.snapshot_copy_grant_name
  }

  depends_on = [aws_redshift_cluster.primary]

  lifecycle {
    ignore_changes = [master_password]
  }

  tags = {
    Name        = "Primary Redshift Cluster"
    Environment = "Production"
  }
}

