provider "aws" {
  region = "us-east-1"
}

# IAM Role for Lambda
resource "aws_iam_role" "lambda_role" {
  name = "lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic Lambda execution policy
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
  role       = aws_iam_role.lambda_role.name
}

# Lambda function code
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function.zip"

  source {
    content  = <<EOF
def lambda_handler(event, context):
    print("Lambda function invoked by EventBridge")
    return {
        'statusCode': 200,
        'body': 'Function executed successfully'
    }
EOF
    filename = "lambda_function.py"
  }
}

# Lambda Function
resource "aws_lambda_function" "scheduled_function" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "scheduled_lambda_function"
  role            = aws_iam_role.lambda_role.arn
  handler         = "lambda_function.lambda_handler"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  runtime         = "python3.11"
  timeout         = 60

  environment {
    variables = {
      ENVIRONMENT = "production"
    }
  }
}

# CloudWatch Event Rule (EventBridge) - triggers every 15 minutes
resource "aws_cloudwatch_event_rule" "every_15_minutes" {
  name                = "trigger-lambda-every-15-minutes"
  description         = "Trigger Lambda function every 15 minutes"
  schedule_expression = "rate(15 minutes)"
}

# CloudWatch Event Target
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.every_15_minutes.name
  target_id = "TargetLambdaFunction"
  arn       = aws_lambda_function.scheduled_function.arn
}

# Lambda permission for EventBridge to invoke
resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.scheduled_function.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.every_15_minutes.arn
}

output "lambda_function_name" {
  value = aws_lambda_function.scheduled_function.function_name
}

output "lambda_function_arn" {
  value = aws_lambda_function.scheduled_function.arn
}

output "eventbridge_rule_name" {
  value = aws_cloudwatch_event_rule.every_15_minutes.name
}

