      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Example metric alarms to be used in the composite alarm
resource "aws_cloudwatch_metric_alarm" "cpu_alarm" {
  alarm_name          = "high-cpu-alarm"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = 2
  metric_name         = "CPUUtilization"
  namespace           = "AWS/EC2"
  period              = 300
  statistic           = "Average"
  threshold           = 80
  alarm_description   = "This metric monitors ec2 cpu utilization"
  treat_missing_data  = "notBreaching"
}

resource "aws_cloudwatch_metric_alarm" "memory_alarm" {
  alarm_name          = "high-memory-alarm"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = 2
  metric_name         = "MemoryUtilization"
  namespace           = "CWAgent"
  period              = 300
  statistic           = "Average"
  threshold           = 85
  alarm_description   = "This metric monitors memory utilization"
  treat_missing_data  = "notBreaching"
}

resource "aws_cloudwatch_metric_alarm" "disk_alarm" {
  alarm_name          = "high-disk-alarm"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = 1
  metric_name         = "DiskSpaceUtilization"
  namespace           = "CWAgent"
  period              = 300
  statistic           = "Average"
  threshold           = 90
  alarm_description   = "This metric monitors disk utilization"
  treat_missing_data  = "notBreaching"
}

# Composite Alarm using AND logic
resource "aws_cloudwatch_composite_alarm" "composite_alarm_and" {
  alarm_name          = "composite-alarm-and"
  alarm_description   = "Composite alarm that triggers when both CPU AND memory are high"
  actions_enabled     = true
  alarm_actions       = []
  ok_actions          = []
  insufficient_data_actions = []

  alarm_rule = "ALARM(${aws_cloudwatch_metric_alarm.cpu_alarm.alarm_name}) AND ALARM(${aws_cloudwatch_metric_alarm.memory_alarm.alarm_name})"

  tags = {
    Environment = "production"
    Name        = "composite-alarm-and"
  }
}

# Composite Alarm using OR logic
resource "aws_cloudwatch_composite_alarm" "composite_alarm_or" {
  alarm_name          = "composite-alarm-or"
  alarm_description   = "Composite alarm that triggers when CPU OR memory OR disk are high"
  actions_enabled     = true
  alarm_actions       = []

  alarm_rule = join(" OR ", [
    "ALARM(${aws_cloudwatch_metric_alarm.cpu_alarm.alarm_name})",
    "ALARM(${aws_cloudwatch_metric_alarm.memory_alarm.alarm_name})",
    "ALARM(${aws_cloudwatch_metric_alarm.disk_alarm.alarm_name})"
  ])

  tags = {
    Environment = "production"
    Name        = "composite-alarm-or"
  }
}

# Composite Alarm with complex logic
resource "aws_cloudwatch_composite_alarm" "composite_alarm_complex" {
  alarm_name          = "composite-alarm-complex"
  alarm_description   = "Composite alarm with complex logic: (CPU AND Memory) OR Disk"
  actions_enabled     = true
  alarm_actions       = []

  alarm_rule = "(ALARM(${aws_cloudwatch_metric_alarm.cpu_alarm.alarm_name}) AND ALARM(${aws_cloudwatch_metric_alarm.memory_alarm.alarm_name})) OR ALARM(${aws_cloudwatch_metric_alarm.disk_alarm.alarm_name})"

  actions_suppressor {
    alarm            = aws_cloudwatch_metric_alarm.cpu_alarm.alarm_name
    extension_period = 300
    wait_period      = 60
  }

  tags = {
    Environment = "production"
    Name        = "composite-alarm-complex"
  }
}

