provider "aws" {
  region = "us-east-1"
}

# DynamoDB Table
resource "aws_dynamodb_table" "example" {
  name           = "example-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"
  stream_enabled = true
  stream_view_type = "NEW_AND_OLD_IMAGES"

  attribute {
    name = "id"
    type = "S"
  }

  tags = {
    Name        = "example-dynamodb-table"
    Environment = "dev"
  }
}

# Kinesis Data Stream
resource "aws_kinesis_stream" "example" {
  name             = "example-kinesis-stream"
  shard_count      = 1
  retention_period = 24

  shard_level_metrics = [
    "IncomingBytes",
    "IncomingRecords",
    "OutgoingBytes",
    "OutgoingRecords",
  ]

  tags = {
    Name        = "example-kinesis-stream"
    Environment = "dev"
  }
}

# IAM Role for Kinesis Streaming Destination
resource "aws_iam_role" "kinesis_streaming_destination" {
  name = "dynamodb-kinesis-streaming-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dynamodb.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name        = "dynamodb-kinesis-streaming-role"
    Environment = "dev"
  }
}

# IAM Policy for Kinesis Streaming Destination
resource "aws_iam_role_policy" "kinesis_streaming_destination" {
  name = "dynamodb-kinesis-streaming-policy"
  role = aws_iam_role.kinesis_streaming_destination.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:PutRecord",
          "kinesis:PutRecords",
          "kinesis:DescribeStream"
        ]
        Resource = aws_kinesis_stream.example.arn
      }
    ]
  })
}

# Kinesis Streaming Destination for DynamoDB
resource "aws_dynamodb_kinesis_streaming_destination" "example" {
  stream_arn = aws_kinesis_stream.example.arn
  table_name = aws_dynamodb_table.example.name

  depends_on = [
    aws_iam_role_policy.kinesis_streaming_destination
  ]
}

# Outputs
output "dynamodb_table_name" {
  description = "Name of the DynamoDB table"
  value       = aws_dynamodb_table.example.name
}

output "kinesis_stream_name" {
  description = "Name of the Kinesis stream"
  value       = aws_kinesis_stream.example.name
}

output "kinesis_stream_arn" {
  description = "ARN of the Kinesis stream"
  value       = aws_kinesis_stream.example.arn
}

output "streaming_destination_status" {
  description = "Status of the Kinesis streaming destination"
  value       = aws_dynamodb_kinesis_streaming_destination.example.id
}

