provider "aws" {
  alias  = "primary"
  region = "us-east-1"
}

# Secondary region provider for replica
provider "aws" {
  alias  = "secondary"
  region = "us-west-2"
}

# DynamoDB Global Table
resource "aws_dynamodb_table" "global_table" {
  provider         = aws.primary
  name             = "my-global-table"
