  description = "ARN of the DynamoDB Global Table"
  value       = aws_dynamodb_table.global_table.arn
}

output "replica_arns" {
  description = "ARNs of the DynamoDB Table replicas"
  value       = aws_dynamodb_table.global_table.replica[*].arn
}

