terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM Role for SageMaker Pipeline
resource "aws_iam_role" "sagemaker_pipeline_role" {
  name = "sagemaker-pipeline-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for SageMaker Pipeline
resource "aws_iam_role_policy" "sagemaker_pipeline_policy" {
  name = "sagemaker-pipeline-policy"
  role = aws_iam_role.sagemaker_pipeline_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject",
          "s3:ListBucket"
        ]
        Resource = [
          "arn:aws:s3:::*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "sagemaker:*"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

# SageMaker Pipeline
resource "aws_sagemaker_pipeline" "example_pipeline" {
  pipeline_name         = "example-ml-pipeline"
  pipeline_display_name = "Example ML Pipeline"
  role_arn              = aws_iam_role.sagemaker_pipeline_role.arn

  pipeline_definition = jsonencode({
    Version = "2020-12-01"
    Parameters = [
      {
        Name         = "InputDataUrl"
        Type         = "String"
        DefaultValue = "s3://my-bucket/data/input.csv"
      },
      {
        Name         = "InstanceType"
        Type         = "String"
        DefaultValue = "ml.m5.xlarge"
      }
    ]
    Steps = [
      {
        Name = "ProcessingStep"
        Type = "Processing"
        Arguments = {
          ProcessingResources = {
            ClusterConfig = {
              InstanceCount = 1
              InstanceType  = "ml.m5.xlarge"
              VolumeSizeInGB = 30
            }
          }
          AppSpecification = {
            ImageUri = "683313688378.dkr.ecr.us-east-1.amazonaws.com/sagemaker-scikit-learn:0.23-1-cpu-py3"
          }
          RoleArn = aws_iam_role.sagemaker_pipeline_role.arn
        }
      }
    ]
  })

  tags = {
    Name        = "example-pipeline"
    Environment = "development"
  }
}

output "pipeline_arn" {
  description = "ARN of the SageMaker Pipeline"
  value       = aws_sagemaker_pipeline.example_pipeline.arn
}

output "pipeline_name" {
  description = "Name of the SageMaker Pipeline"
  value       = aws_sagemaker_pipeline.example_pipeline.pipeline_name
}

