# ElastiCache Redis Cluster for Database Query Caching
resource "aws_elasticache_cluster" "redis_cache" {
  cluster_id           = "db-query-cache"
  engine               = "redis"
  node_type            = "cache.t3.micro"
  num_cache_nodes      = 1
  parameter_group_name = "default.redis7"
  engine_version       = "7.0"
  port                 = 6379

  subnet_group_name    = aws_elasticache_subnet_group.redis_subnet_group.name
  security_group_ids   = [aws_security_group.redis_sg.id]

  tags = {
    Name        = "database-cache"
    Purpose     = "Reduce database calls"
    Environment = "production"
  }
}

# Subnet Group for ElastiCache
resource "aws_elasticache_subnet_group" "redis_subnet_group" {
  name       = "redis-cache-subnet-group"
  subnet_ids = var.subnet_ids

  tags = {
    Name = "Redis cache subnet group"
  }
}

# Security Group for Redis
resource "aws_security_group" "redis_sg" {
  name        = "redis-cache-sg"
  description = "Security group for Redis cache cluster"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = var.allowed_cidr_blocks
    description = "Allow Redis access from application servers"
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
    description = "Allow all outbound traffic"
  }

  tags = {
    Name = "redis-cache-security-group"
  }
}

# Variables
variable "vpc_id" {
  description = "VPC ID where Redis will be deployed"
  type        = string
}

variable "subnet_ids" {
  description = "List of subnet IDs for ElastiCache subnet group"
  type        = list(string)
}

variable "allowed_cidr_blocks" {
  description = "CIDR blocks allowed to access Redis"
  type        = list(string)
  default     = ["10.0.0.0/16"]
}

# Outputs
output "redis_endpoint" {
  description = "Redis cache endpoint for application configuration"
  value       = aws_elasticache_cluster.redis_cache.cache_nodes[0].address
}

output "redis_port" {
  description = "Redis cache port"
  value       = aws_elasticache_cluster.redis_cache.port
}

output "redis_connection_string" {
  description = "Full Redis connection string"
  value       = "${aws_elasticache_cluster.redis_cache.cache_nodes[0].address}:${aws_elasticache_cluster.redis_cache.port}"
}

