terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM Role for ElastiCache authentication
resource "aws_iam_role" "elasticache_user_role" {
  name = "elasticache-user-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticache.amazonaws.com"
        }
      },
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          AWS = data.aws_caller_identity.current.arn
        }
      }
    ]
  })
}

# IAM Policy for ElastiCache access
resource "aws_iam_role_policy" "elasticache_access_policy" {
  name = "elasticache-access-policy"
  role = aws_iam_role.elasticache_user_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "elasticache:Connect"
        ]
        Resource = aws_elasticache_replication_group.redis.arn
      }
    ]
  })
}

# ElastiCache Subnet Group
resource "aws_elasticache_subnet_group" "redis" {
  name       = "redis-subnet-group"
  subnet_ids = var.subnet_ids
}

# ElastiCache Replication Group with IAM authentication enabled
resource "aws_elasticache_replication_group" "redis" {
  replication_group_id       = "redis-cluster"
  description                = "Redis cluster with IAM authentication"
  engine                     = "redis"
  engine_version             = "7.0"
  node_type                  = "cache.t3.micro"
  num_cache_clusters         = 2
  port                       = 6379
  parameter_group_name       = aws_elasticache_parameter_group.redis.name
  subnet_group_name          = aws_elasticache_subnet_group.redis.name
  security_group_ids         = [aws_security_group.elasticache.id]
  transit_encryption_enabled = true
  auth_token_enabled         = false

  # Enable IAM authentication
  user_group_ids = [aws_elasticache_user_group.iam_enabled.id]

  automatic_failover_enabled = true
  multi_az_enabled           = true

  tags = {
    Name = "redis-iam-enabled"
  }
}

# ElastiCache Parameter Group
resource "aws_elasticache_parameter_group" "redis" {
  name   = "redis-params"
  family = "redis7"
}

# ElastiCache User with IAM authentication
resource "aws_elasticache_user" "iam_user" {
  user_id       = "iam-enabled-user"
  user_name     = "default"
  access_string = "on ~* &* +@all"
  engine        = "REDIS"

  authentication_mode {
    type = "iam"
  }
}

# ElastiCache User Group
resource "aws_elasticache_user_group" "iam_enabled" {
  engine        = "REDIS"
  user_group_id = "iam-user-group"
  user_ids      = [aws_elasticache_user.iam_user.user_id]
}

# Security Group for ElastiCache
resource "aws_security_group" "elasticache" {
  name        = "elasticache-sg"
  description = "Security group for ElastiCache"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "elasticache-sg"
  }
}

# Data source for current AWS account
data "aws_caller_identity" "current" {}

# Variables
variable "vpc_id" {
  description = "VPC ID for ElastiCache"
  type        = string
}

variable "subnet_ids" {
  description = "Subnet IDs for ElastiCache"
  type        = list(string)
}

# Outputs
output "replication_group_id" {
  value       = aws_elasticache_replication_group.redis.id
  description = "ElastiCache Replication Group ID"
}

output "primary_endpoint" {
  value       = aws_elasticache_replication_group.redis.primary_endpoint_address
  description = "Primary endpoint address"
}

output "iam_user_id" {
  value       = aws_elasticache_user.iam_user.user_id
  description = "ElastiCache IAM user ID"
}

output "iam_role_arn" {
  value       = aws_iam_role.elasticache_user_role.arn
  description = "IAM Role ARN for ElastiCache authentication"
}

