        Effect = "Allow"
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = [
          "${aws_cloudwatch_log_group.msk_log_group.arn}:*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject"
        ]
        Resource = [
          "${aws_s3_bucket.msk_logs.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "firehose:PutRecord",
          "firehose:PutRecordBatch"
        ]
        Resource = [
          aws_kinesis_firehose_delivery_stream.msk_stream.arn
        ]
      }
    ]
  })
}

# KMS Key for Encryption at Rest
resource "aws_kms_key" "msk_kms_key" {
  description             = "KMS key for MSK encryption at rest"
  deletion_window_in_days = 10

  tags = {
    Name = "msk-kms-key"
  }
}

resource "aws_kms_alias" "msk_kms_alias" {
  name          = "alias/msk-key"
  target_key_id = aws_kms_key.msk_kms_key.key_id
}

# MSK Configuration
resource "aws_msk_configuration" "msk_config" {
  name              = "msk-cluster-config"
  kafka_versions    = ["3.5.1"]
  server_properties = <<PROPERTIES
auto.create.topics.enable=true
delete.topic.enable=true
log.retention.hours=168
PROPERTIES
}

# MSK Cluster
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = [
      aws_subnet.msk_subnet_az1.id,
      aws_subnet.msk_subnet_az2.id,
      aws_subnet.msk_subnet_az3.id
    ]
    security_groups = [aws_security_group.msk_sg.id]

    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_kms_key.arn
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  configuration_info {
    arn      = aws_msk_configuration.msk_config.arn
    revision = aws_msk_configuration.msk_config.latest_revision
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_logs.id
        prefix  = "msk-logs/"
      }
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_stream.name
      }
    }
  }

  tags = {
    Name = "msk-cluster"
  }
}

output "msk_cluster_arn" {
  value       = aws_msk_cluster.msk_cluster.arn
  description = "ARN of the MSK cluster"
}

output "msk_bootstrap_brokers_tls" {
  value       = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls
  description = "TLS connection host:port pairs"
}

output "msk_zookeeper_connect_string" {
  value       = aws_msk_cluster.msk_cluster.zookeeper_connect_string
  description = "Zookeeper connection string"
}

output "cloudwatch_log_group_name" {
  value       = aws_cloudwatch_log_group.msk_log_group.name
  description = "CloudWatch log group name"
}

output "s3_bucket_name" {
  value       = aws_s3_bucket.msk_logs.id
  description = "S3 bucket name for MSK logs"
}

output "firehose_delivery_stream_name" {
  value       = aws_kinesis_firehose_delivery_stream.msk_stream.name
  description = "Kinesis Firehose delivery stream name"
}
