  }
}

resource "aws_internet_gateway" "msk_igw" {
  vpc_id = aws_vpc.msk_vpc.id

  tags = {
    Name = "msk-igw"
  }
}

resource "aws_route_table" "msk_route_table" {
  vpc_id = aws_vpc.msk_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.msk_igw.id
  }

  tags = {
    Name = "msk-route-table"
  }
}

resource "aws_route_table_association" "msk_rta_az1" {
  subnet_id      = aws_subnet.msk_subnet_az1.id
  route_table_id = aws_route_table.msk_route_table.id
}

resource "aws_route_table_association" "msk_rta_az2" {
  subnet_id      = aws_subnet.msk_subnet_az2.id
  route_table_id = aws_route_table.msk_route_table.id
}

resource "aws_route_table_association" "msk_rta_az3" {
  subnet_id      = aws_subnet.msk_subnet_az3.id
  route_table_id = aws_route_table.msk_route_table.id
}

# Security Group
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Security group for MSK cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

# CloudWatch Log Group
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name              = "/aws/msk/cluster"
  retention_in_days = 7
}

# MSK Cluster Configuration
resource "aws_msk_configuration" "msk_config" {
  name              = "msk-cluster-config"
  kafka_versions    = ["3.5.1"]
  server_properties = <<PROPERTIES
auto.create.topics.enable=true
default.replication.factor=3
min.insync.replicas=2
num.io.threads=8
num.network.threads=5
num.partitions=1
num.replica.fetchers=2
replica.lag.time.max.ms=30000
socket.receive.buffer.bytes=102400
socket.request.max.bytes=104857600
socket.send.buffer.bytes=102400
unclean.leader.election.enable=true
zookeeper.session.timeout.ms=18000
PROPERTIES
}

# MSK Cluster
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
    client_subnets = [
      aws_subnet.msk_subnet_az1.id,
      aws_subnet.msk_subnet_az2.id,
      aws_subnet.msk_subnet_az3.id
    ]
    security_groups = [aws_security_group.msk_sg.id]
  }

  configuration_info {
    arn      = aws_msk_configuration.msk_config.arn
    revision = aws_msk_configuration.msk_config.latest_revision
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
    }
  }

  tags = {
    Name = "msk-cluster"
  }
}

# S3 Bucket for MSK Connect Plugin
resource "aws_s3_bucket" "msk_connect_bucket" {
  bucket = "msk-connect-plugins-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name = "msk-connect-plugins"
  }
}

resource "aws_s3_object" "debezium_plugin" {
  bucket = aws_s3_bucket.msk_connect_bucket.id
  key    = "debezium.zip"
  source = "debezium.zip"
  etag   = filemd5("debezium.zip")
}

# IAM Role for MSK Connect
resource "aws_iam_role" "msk_connect_role" {
  name = "msk-connect-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "msk_connect_policy" {
  name = "msk-connect-policy"
  role = aws_iam_role.msk_connect_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kafka-cluster:Connect",
          "kafka-cluster:AlterCluster",
          "kafka-cluster:DescribeCluster"
        ]
        Resource = aws_msk_cluster.msk_cluster.arn
      },
      {
        Effect = "Allow"
        Action = [
          "kafka-cluster:*Topic*",
          "kafka-cluster:WriteData",
          "kafka-cluster:ReadData"
        ]
        Resource = "arn:aws:kafka:us-east-1:${data.aws_caller_identity.current.account_id}:topic/${aws_msk_cluster.msk_cluster.cluster_name}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "kafka-cluster:AlterGroup",
          "kafka-cluster:DescribeGroup"
        ]
        Resource = "arn:aws:kafka:us-east-1:${data.aws_caller_identity.current.account_id}:group/${aws_msk_cluster.msk_cluster.cluster_name}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          "${aws_s3_bucket.msk_connect_bucket.arn}",
          "${aws_s3_bucket.msk_connect_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs"
        ]
        Resource = "*"
      }
    ]
  })
}

# MSK Connect Custom Plugin
resource "aws_mskconnect_custom_plugin" "debezium_plugin" {
  name         = "debezium-plugin"
  content_type = "ZIP"

  location {
    s3 {
      bucket_arn = aws_s3_bucket.msk_connect_bucket.arn
      file_key   = aws_s3_object.debezium_plugin.key
    }
  }
}

# CloudWatch Log Group for MSK Connect
resource "aws_cloudwatch_log_group" "msk_connect_log_group" {
  name              = "/aws/msk-connect/connector"
  retention_in_days = 7
}

# MSK Connect Connector
resource "aws_mskconnect_connector" "debezium_connector" {
  name = "debezium-connector"

  kafkaconnect_version = "2.7.1"

  capacity {
    autoscaling {
      mcu_count        = 1
      min_worker_count = 1
      max_worker_count = 2

      scale_in_policy {
        cpu_utilization_percentage = 20
      }

      scale_out_policy {
        cpu_utilization_percentage = 80
      }
    }
  }

  connector_configuration = {
    "connector.class"                = "io.debezium.connector.mysql.MySqlConnector"
    "tasks.max"                      = "1"
    "database.hostname"              = "localhost"
    "database.port"                  = "3306"
    "database.user"                  = "debezium"
    "database.password"              = "dbz"
    "database.server.id"             = "184054"
    "database.server.name"           = "dbserver1"
    "database.include.list"          = "inventory"
    "database.history.kafka.bootstrap.servers" = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls
    "database.history.kafka.topic"   = "schema-changes.inventory"
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls

      vpc {
        security_groups = [aws_security_group.msk_sg.id]
        subnets = [
          aws_subnet.msk_subnet_az1.id,
          aws_subnet.msk_subnet_az2.id,
          aws_subnet.msk_subnet_az3.id
        ]
      }
    }
  }

  kafka_cluster_client_authentication {
    authentication_type = "NONE"
  }

  kafka_cluster_encryption_in_transit {
    encryption_type = "TLS"
  }

  plugin {
    custom_plugin {
      arn      = aws_mskconnect_custom_plugin.debezium_plugin.arn
      revision = aws_mskconnect_custom_plugin.debezium_plugin.latest_revision
    }
  }

  log_delivery {
    worker_log_delivery {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_connect_log_group.name
      }
    }
  }

  service_execution_role_arn = aws_iam_role.msk_connect_role.arn

  depends_on = [aws_msk_cluster.msk_cluster]
}

