terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM role for DAX cluster
resource "aws_iam_role" "dax_cluster_role" {
  name = "dax-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy attachment for DAX to access DynamoDB
resource "aws_iam_role_policy_attachment" "dax_dynamodb_access" {
  role       = aws_iam_role.dax_cluster_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDynamoDBFullAccess"
}

# Subnet group for DAX cluster
resource "aws_dax_subnet_group" "dax_subnet_group" {
  name       = "dax-subnet-group"
  subnet_ids = [aws_subnet.dax_subnet_1.id, aws_subnet.dax_subnet_2.id]
}

# VPC for DAX cluster
resource "aws_vpc" "dax_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "dax-vpc"
  }
}

# Subnets for DAX cluster
resource "aws_subnet" "dax_subnet_1" {
  vpc_id            = aws_vpc.dax_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "dax-subnet-1"
  }
}

resource "aws_subnet" "dax_subnet_2" {
  vpc_id            = aws_vpc.dax_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "dax-subnet-2"
  }
}

# Security group for DAX cluster
resource "aws_security_group" "dax_security_group" {
  name        = "dax-security-group"
  description = "Security group for DAX cluster"
  vpc_id      = aws_vpc.dax_vpc.id

  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "dax-security-group"
  }
}

# DAX cluster
resource "aws_dax_cluster" "dax_cluster" {
  cluster_name       = "my-dax-cluster"
  iam_role_arn       = aws_iam_role.dax_cluster_role.arn
  node_type          = "dax.t3.small"
  replication_factor = 3
  subnet_group_name  = aws_dax_subnet_group.dax_subnet_group.name
  security_group_ids = [aws_security_group.dax_security_group.id]

  tags = {
    Name = "my-dax-cluster"
  }
}

output "dax_cluster_endpoint" {
  description = "DAX cluster configuration endpoint"
  value       = aws_dax_cluster.dax_cluster.configuration_endpoint
}

output "dax_cluster_arn" {
  description = "DAX cluster ARN"
  value       = aws_dax_cluster.dax_cluster.arn
}

