# DynamoDB table with TTL enabled
resource "aws_dynamodb_table" "example" {
  name           = "example-table-with-ttl"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
