          "id": {"S": "item-1"},
          "data": {"S": "This item will expire"},
          "expiration_time": {"N": "${timestamp() + 86400}"}
        }' \n        --region us-east-1
    EOT
  }

  depends_on = [aws_dynamodb_table.example]
}

