    Name = "vpc1-to-vpc2-peering"
  }
}

# Route table for VPC1
resource "aws_route_table" "vpc1_route_table" {
  vpc_id = aws_vpc.vpc1.id

  route {
    cidr_block                = aws_vpc.vpc2.cidr_block
    vpc_peering_connection_id = aws_vpc_peering_connection.vpc1_to_vpc2.id
  }

  tags = {
    Name = "vpc1-route-table"
  }
}

# Route table for VPC2
resource "aws_route_table" "vpc2_route_table" {
  vpc_id = aws_vpc.vpc2.id

  route {
    cidr_block                = aws_vpc.vpc1.cidr_block
    vpc_peering_connection_id = aws_vpc_peering_connection.vpc1_to_vpc2.id
  }

  tags = {
    Name = "vpc2-route-table"
  }
}

# Associate route table with VPC1 main route table
resource "aws_main_route_table_association" "vpc1_main_rt_association" {
  vpc_id         = aws_vpc.vpc1.id
  route_table_id = aws_route_table.vpc1_route_table.id
}

# Associate route table with VPC2 main route table
resource "aws_main_route_table_association" "vpc2_main_rt_association" {
  vpc_id         = aws_vpc.vpc2.id
  route_table_id = aws_route_table.vpc2_route_table.id
}

# Outputs
output "vpc1_id" {
  description = "ID of VPC 1"
  value       = aws_vpc.vpc1.id
}

output "vpc2_id" {
  description = "ID of VPC 2"
  value       = aws_vpc.vpc2.id
}

output "peering_connection_id" {
  description = "ID of the VPC peering connection"
  value       = aws_vpc_peering_connection.vpc1_to_vpc2.id
}
```

