terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC and networking for Neptune
resource "aws_vpc" "neptune_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "neptune-vpc"
  }
}

resource "aws_subnet" "neptune_subnet_1" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "neptune-subnet-1"
  }
}

resource "aws_subnet" "neptune_subnet_2" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "neptune-subnet-2"
  }
}

# Neptune subnet group
resource "aws_neptune_subnet_group" "neptune_subnet_group" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.neptune_subnet_1.id, aws_subnet.neptune_subnet_2.id]

  tags = {
    Name = "neptune-subnet-group"
  }
}

# Security group for Neptune
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-security-group"
  description = "Security group for Neptune cluster"
  vpc_id      = aws_vpc.neptune_vpc.id

  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
    description = "Neptune port"
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-security-group"
  }
}

# Custom Neptune cluster parameter group
resource "aws_neptune_cluster_parameter_group" "custom_neptune_cluster_params" {
  family      = "neptune1.3"
  name        = "custom-neptune-cluster-params"
  description = "Custom parameter group for Neptune cluster"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }

  parameter {
    name  = "neptune_query_timeout"
    value = "120000"
  }

  tags = {
    Name = "custom-neptune-cluster-params"
  }
}

# Custom Neptune instance parameter group
resource "aws_neptune_parameter_group" "custom_neptune_instance_params" {
  family      = "neptune1.3"
  name        = "custom-neptune-instance-params"
  description = "Custom parameter group for Neptune instances"

  parameter {
    name  = "neptune_query_timeout"
    value = "120000"
  }

  tags = {
    Name = "custom-neptune-instance-params"
  }
}

# Neptune cluster
resource "aws_neptune_cluster" "neptune_cluster" {
  cluster_identifier                   = "neptune-cluster"
  engine                               = "neptune"
  engine_version                       = "1.3.2.1"
  backup_retention_period              = 7
  preferred_backup_window              = "03:00-04:00"
  preferred_maintenance_window         = "mon:04:00-mon:05:00"
  skip_final_snapshot                  = true
  iam_database_authentication_enabled  = true
  apply_immediately                    = true
  neptune_subnet_group_name            = aws_neptune_subnet_group.neptune_subnet_group.name
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.custom_neptune_cluster_params.name
  vpc_security_group_ids               = [aws_security_group.neptune_sg.id]

  tags = {
    Name = "neptune-cluster"
  }
}

# Neptune cluster instance
resource "aws_neptune_cluster_instance" "neptune_instance" {
  count                        = 1
  cluster_identifier           = aws_neptune_cluster.neptune_cluster.id
  engine                       = "neptune"
  instance_class               = "db.t3.medium"
  identifier                   = "neptune-instance-${count.index + 1}"
  neptune_parameter_group_name = aws_neptune_parameter_group.custom_neptune_instance_params.name
  apply_immediately            = true

  tags = {
    Name = "neptune-instance-${count.index + 1}"
  }
}

# Outputs
output "neptune_cluster_endpoint" {
  description = "Neptune cluster endpoint"
  value       = aws_neptune_cluster.neptune_cluster.endpoint
}

output "neptune_cluster_reader_endpoint" {
  description = "Neptune cluster reader endpoint"
  value       = aws_neptune_cluster.neptune_cluster.reader_endpoint
}

output "neptune_cluster_port" {
  description = "Neptune cluster port"
  value       = aws_neptune_cluster.neptune_cluster.port
}

