  }
}

# Security Group - only allow connections from the two subnets
resource "aws_security_group" "neptune" {
  name        = "neptune-sg"
  description = "Security group for Neptune cluster - allows connections from two subnets only"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "Neptune from subnet 1"
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.subnet_1.cidr_block]
  }

  ingress {
    description = "Neptune from subnet 2"
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.subnet_2.cidr_block]
  }

  egress {
    description = "Allow all outbound traffic"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-sg"
  }
}

# Neptune Cluster Parameter Group
resource "aws_neptune_cluster_parameter_group" "main" {
  name        = "neptune-custom-params"
  family      = "neptune1.3"
  description = "Custom parameter group for Neptune cluster"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }

  tags = {
    Name = "neptune-custom-params"
  }
}

# Neptune DB Parameter Group
resource "aws_neptune_parameter_group" "main" {
  name        = "neptune-db-custom-params"
  family      = "neptune1.3"
  description = "Custom DB parameter group for Neptune instances"

  tags = {
    Name = "neptune-db-custom-params"
  }
}

