extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# AWS Chime Voice Connector
resource "aws_chime_voice_connector" "main" {
  name               = "my-voice-connector"
  require_encryption = true
  aws_region         = "us-east-1"
}

# IAM Role for Kinesis streaming
resource "aws_iam_role" "chime_kinesis_role" {
  name = "chime-kinesis-streaming-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "voiceconnector.chime.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Kinesis streaming
resource "aws_iam_role_policy" "chime_kinesis_policy" {
  name = "chime-kinesis-streaming-policy"
  role = aws_iam_role.chime_kinesis_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesisvideo:PutMedia",
          "kinesisvideo:DescribeStream",
          "kinesisvideo:GetDataEndpoint"
        ]
        Resource = "*"
      }
    ]
  })
}

# Kinesis Video Stream
resource "aws_kinesisvideo_stream" "chime_stream" {
  name                    = "chime-media-stream"
  data_retention_in_hours = 24
  media_type              = "video/h264,audio/aac"

  tags = {
    Name = "chime-media-stream"
  }
}

# Chime Voice Connector Streaming Configuration
resource "aws_chime_voice_connector_streaming" "main" {
  voice_connector_id = aws_chime_voice_connector.main.id
  disabled           = false
  data_retention     = 24

  streaming_notification_targets = ["EventBridge"]

  media_insights_configuration {
    disabled           = false
    configuration_arn  = aws_iam_role.chime_kinesis_role.arn
  }
}

# Outputs
output "voice_connector_id" {
  value       = aws_chime_voice_connector.main.id
  description = "The ID of the Chime Voice Connector"
}

output "voice_connector_outbound_host_name" {
  value       = aws_chime_voice_connector.main.outbound_host_name
  description = "The outbound hostname for the Voice Connector"
}

output "kinesis_video_stream_arn" {
  value       = aws_kinesisvideo_stream.chime_stream.arn
  description = "The ARN of the Kinesis Video Stream"
}

