  }

  parameter {
    name  = "enable_user_activity_logging"
    value = "true"
  }

  parameter {
    name  = "max_cursor_result_set_size"
    value = "default"
  }

  parameter {
    name  = "query_group"
    value = "default"
  }

  parameter {
    name  = "wlm_json_configuration"
    value = "[{"query_concurrency":5}]"
  }
}

# Redshift Event Subscription for Parameter Group
resource "aws_redshift_event_subscription" "parameter_group_events" {
  name          = "redshift-parameter-group-subscription"
  sns_topic_arn = aws_sns_topic.redshift_events.arn
  source_type   = "cluster-parameter-group"
  source_ids    = [aws_redshift_parameter_group.example.id]

  event_categories = [
    "configuration"
  ]

  enabled = true
}

# Redshift Subnet Group
resource "aws_redshift_subnet_group" "example" {
  name       = "example-redshift-subnet-group"
  subnet_ids = [aws_subnet.example_1.id, aws_subnet.example_2.id]

  tags = {
    Name = "Example Redshift Subnet Group"
  }
}

# VPC for Redshift
resource "aws_vpc" "example" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

# Subnets
resource "aws_subnet" "example_1" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "example_2" {
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-2"
  }
}

# Security Group for Redshift
resource "aws_security_group" "redshift" {
  name        = "redshift-sg"
  description = "Security group for Redshift cluster"
  vpc_id      = aws_vpc.example.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-security-group"
  }
}

# IAM Role for Redshift
resource "aws_iam_role" "redshift" {
  name = "redshift-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "redshift_s3" {
  role       = aws_iam_role.redshift.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# Redshift Cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier  = "example-redshift-cluster"
  database_name       = "exampledb"
  master_username     = "admin"
  master_password     = "MyPassword123!"
  node_type           = "dc2.large"
  cluster_type        = "single-node"
  cluster_parameter_group_name = aws_redshift_parameter_group.example.name

  cluster_subnet_group_name    = aws_redshift_subnet_group.example.name
  vpc_security_group_ids       = [aws_security_group.redshift.id]

  publicly_accessible          = false
  encrypted                    = true
  skip_final_snapshot         = true

  iam_roles = [aws_iam_role.redshift.arn]

  tags = {
    Name        = "example-redshift-cluster"
    Environment = "development"
  }
}

output "redshift_cluster_endpoint" {
  description = "Redshift cluster endpoint"
  value       = aws_redshift_cluster.example.endpoint
}

output "redshift_cluster_id" {
  description = "Redshift cluster identifier"
  value       = aws_redshift_cluster.example.id
}

output "sns_topic_arn" {
  description = "SNS topic ARN for Redshift events"
  value       = aws_sns_topic.redshift_events.arn
}

