terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create an IAM group
resource "aws_iam_group" "developers" {
  name = "developers"
  path = "/users/"
}

# Create an IAM policy
resource "aws_iam_policy" "developer_policy" {
  name        = "DeveloperPolicy"
  description = "Policy for developers group"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "ec2:Describe*",
          "s3:ListBucket",
          "s3:GetObject"
        ]
        Resource = "*"
      }
    ]
  })
}

# Attach policy to group
resource "aws_iam_group_policy_attachment" "developer_policy_attachment" {
  group      = aws_iam_group.developers.name
  policy_arn = aws_iam_policy.developer_policy.arn
}

# Create IAM users
resource "aws_iam_user" "users" {
  count = 2
  name  = "developer-${count.index + 1}"
  path  = "/users/"
}

# Add users to the group
resource "aws_iam_group_membership" "developers_membership" {
  name  = "developers-group-membership"
  group = aws_iam_group.developers.name

  users = aws_iam_user.users[*].name
}

# Outputs
output "group_name" {
  value       = aws_iam_group.developers.name
  description = "The name of the IAM group"
}

output "group_arn" {
  value       = aws_iam_group.developers.arn
  description = "The ARN of the IAM group"
}

output "user_names" {
  value       = aws_iam_user.users[*].name
  description = "List of IAM user names"
}

