extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 bucket for storing website images
resource "aws_s3_bucket" "website_images" {
  bucket = "website-images-${random_id.bucket_suffix.hex}"

  tags = {
    Name        = "Website Images"
    Environment = "Production"
    Purpose     = "Image Storage"
  }
}

# Random suffix for unique bucket name
resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# Block public access settings
resource "aws_s3_bucket_public_access_block" "website_images" {
  bucket = aws_s3_bucket.website_images.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# Bucket policy for public read access
resource "aws_s3_bucket_policy" "website_images" {
  bucket = aws_s3_bucket.website_images.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.website_images.arn}/*"
      }
    ]
  })

  depends_on = [aws_s3_bucket_public_access_block.website_images]
}

# Enable versioning
resource "aws_s3_bucket_versioning" "website_images" {
  bucket = aws_s3_bucket.website_images.id

  versioning_configuration {
    status = "Enabled"
  }
}

# CORS configuration for web access
resource "aws_s3_bucket_cors_configuration" "website_images" {
  bucket = aws_s3_bucket.website_images.id

  cors_rule {
    allowed_headers = ["*"]
    allowed_methods = ["GET", "HEAD"]
    allowed_origins = ["*"]
    expose_headers  = ["ETag"]
    max_age_seconds = 3000
  }
}

# Server-side encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "website_images" {
  bucket = aws_s3_bucket.website_images.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# Lifecycle rule to manage old versions
resource "aws_s3_bucket_lifecycle_configuration" "website_images" {
  bucket = aws_s3_bucket.website_images.id

  rule {
    id     = "delete-old-versions"
    status = "Enabled"

    noncurrent_version_expiration {
      noncurrent_days = 90
    }
  }
}

# Outputs
output "bucket_name" {
  value       = aws_s3_bucket.website_images.id
  description = "Name of the S3 bucket for website images"
}

output "bucket_arn" {
  value       = aws_s3_bucket.website_images.arn
  description = "ARN of the S3 bucket"
}

output "bucket_url" {
  value       = "https://${aws_s3_bucket.website_images.bucket}.s3.amazonaws.com"
  description = "URL to access images in the bucket"
}

output "bucket_domain_name" {
  value       = aws_s3_bucket.website_images.bucket_domain_name
  description = "Domain name of the bucket"
}

response:
```hcl
