  bucket = "mybucket-inventory"
}

resource "aws_s3_bucket_policy" "inventory_destination_policy" {
  bucket = aws_s3_bucket.inventory_destination.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "InventoryPolicy"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action   = "s3:PutObject"
        Resource = "${aws_s3_bucket.inventory_destination.arn}/*"
        Condition = {
          StringEquals = {
            "s3:x-amz-acl" = "bucket-owner-full-control"
            "aws:SourceAccount" = data.aws_caller_identity.current.account_id
          }
          ArnLike = {
            "aws:SourceArn" = aws_s3_bucket.mybucket.arn
          }
        }
      }
    ]
  })
}

resource "aws_s3_bucket_inventory" "mybucket_inventory" {
  bucket = aws_s3_bucket.mybucket.id
  name   = "EntireBucketDaily"

  included_object_versions = "All"

  schedule {
    frequency = "Daily"
  }

  destination {
    bucket {
      format     = "CSV"
      bucket_arn = aws_s3_bucket.inventory_destination.arn
      prefix     = "inventory"
    }
  }

  depends_on = [aws_s3_bucket_policy.inventory_destination_policy]
}

