provider "aws" {
  region = "us-east-1"
}

# Source bucket for storing objects
resource "aws_s3_bucket" "source" {
  bucket = "my-source-bucket-${random_id.bucket_suffix.hex}"
}

# Inventory destination bucket
resource "aws_s3_bucket" "inventory" {
  bucket = "my-inventory-bucket-${random_id.bucket_suffix.hex}"
}

# Random suffix for unique bucket names
resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# Bucket policy for inventory destination bucket
resource "aws_s3_bucket_policy" "inventory" {
  bucket = aws_s3_bucket.inventory.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "InventoryPolicy"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action   = "s3:PutObject"
        Resource = "${aws_s3_bucket.inventory.arn}/*"
        Condition = {
          StringEquals = {
            "s3:x-amz-acl" = "bucket-owner-full-control"
          }
          ArnLike = {
            "aws:SourceArn" = aws_s3_bucket.source.arn
          }
        }
      }
    ]
  })
}

# S3 Inventory configuration
resource "aws_s3_bucket_inventory" "weekly_csv_inventory" {
  bucket = aws_s3_bucket.source.id
  name   = "weekly-csv-inventory"

  included_object_versions = "Current"

  schedule {
    frequency = "Weekly"
  }

  destination {
    bucket {
      format     = "CSV"
      bucket_arn = aws_s3_bucket.inventory.arn
      prefix     = "inventory-reports"
