terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 bucket for storing autograder results
resource "aws_s3_bucket" "autograder_results" {
  bucket = "autograder-results-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_versioning" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_public_access_block" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# DynamoDB table for tracking grading jobs
resource "aws_dynamodb_table" "grading_jobs" {
  name           = "autograder-jobs"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "student_id"
  range_key      = "submission_timestamp"

  attribute {
    name = "student_id"
    type = "S"
  }

  attribute {
    name = "submission_timestamp"
    type = "N"
  }

  attribute {
    name = "status"
    type = "S"
  }

  global_secondary_index {
    name            = "StatusIndex"
    hash_key        = "status"
    range_key       = "submission_timestamp"
    projection_type = "ALL"
  }
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for CodeBuild
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = [
          "arn:aws:logs:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:log-group:/aws/codebuild/autograder",
          "arn:aws:logs:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:log-group:/aws/codebuild/autograder:*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem",
          "dynamodb:UpdateItem",
          "dynamodb:GetItem"
        ]
        Resource = aws_dynamodb_table.grading_jobs.arn
      }
    ]
  })
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "autograder" {
  name              = "/aws/codebuild/autograder"
  retention_in_days = 30
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograder" {
  name          = "autograder"
  description   = "Autograder for CS class assignments"
  build_timeout = 30
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.id
    }

    environment_variable {
      name  = "DYNAMODB_TABLE"
      value = aws_dynamodb_table.grading_jobs.name
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name = aws_cloudwatch_log_group.autograder.name
      status     = "ENABLED"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-submissions.git"
    git_clone_depth = 1
    buildspec       = <<-EOT
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.11
          commands:
            - echo "Installing dependencies..."
            - pip install -r requirements.txt || echo "No requirements.txt found"
        pre_build:
          commands:
            - echo "Setting up test environment..."
            - export STUDENT_ID=$${STUDENT_ID:-"unknown"}
            - export TIMESTAMP=$(date +%s)
        build:
          commands:
            - echo "Running autograder tests..."
            - python autograder/run_tests.py > test_results.txt 2>&1 || true
        post_build:
          commands:
            - echo "Uploading results to S3..."
            - aws s3 cp test_results.txt s3://$RESULTS_BUCKET/$STUDENT_ID/$TIMESTAMP/results.txt
            - |
              aws dynamodb put-item \n                --table-name $DYNAMODB_TABLE \n                --item "{"student_id": {"S": "$STUDENT_ID"}, "submission_timestamp": {"N": "$TIMESTAMP"}, "status": {"S": "COMPLETED"}, "results_location": {"S": "s3://$RESULTS_BUCKET/$STUDENT_ID/$TIMESTAMP/results.txt"}}"
      artifacts:
        files:
          - test_results.txt
    EOT
  }

  source_version = "main"
}

# GitHub Connection (requires manual OAuth setup in console)
resource "aws_codestarconnections_connection" "github" {
  name          = "github-connection"
  provider_type = "GitHub"
}

# SNS topic for grading notifications
resource "aws_sns_topic" "grading_notifications" {
  name = "autograder-notifications"
}

resource "aws_sns_topic_subscription" "grading_email" {
  topic_arn = aws_sns_topic.grading_notifications.arn
  protocol  = "email"
  endpoint  = "instructor@example.com"
}

# EventBridge rule to notify on build completion
resource "aws_cloudwatch_event_rule" "build_completion" {
  name        = "autograder-build-completion"
  description = "Trigger when CodeBuild autograder completes"

  event_pattern = jsonencode({
    source      = ["aws.codebuild"]
    detail-type = ["CodeBuild Build State Change"]
    detail = {
      build-status = ["SUCCEEDED", "FAILED", "STOPPED"]
      project-name = [aws_codebuild_project.autograder.name]
    }
  })
}

resource "aws_cloudwatch_event_target" "sns" {
  rule      = aws_cloudwatch_event_rule.build_completion.name
  target_id = "SendToSNS"
  arn       = aws_sns_topic.grading_notifications.arn
}

resource "aws_sns_topic_policy" "grading_notifications" {
  arn = aws_sns_topic.grading_notifications.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "events.amazonaws.com"
        }
        Action   = "SNS:Publish"
        Resource = aws_sns_topic.grading_notifications.arn
      }
    ]
  })
}

# Data sources
data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# Outputs
output "codebuild_project_name" {
  value       = aws_codebuild_project.autograder.name
  description = "Name of the CodeBuild project"
}

output "results_bucket_name" {
  value       = aws_s3_bucket.autograder_results.id
  description = "S3 bucket for storing autograder results"
}

output "dynamodb_table_name" {
  value       = aws_dynamodb_table.grading_jobs.name
  description = "DynamoDB table for tracking grading jobs"
}

output "start_build_command" {
  value       = "aws codebuild start-build --project-name ${aws_codebuild_project.autograder.name} --environment-variables-override name=STUDENT_ID,value=<student_id>,type=PLAINTEXT"
  description = "Command to manually start a build for a student"
}

