                "build_id": "$CODEBUILD_BUILD_ID",
                "test_exit_code": $TEST_EXIT_CODE,
                "commit_sha": "$CODEBUILD_RESOLVED_SOURCE_VERSION"
              }" > result.json
              aws s3 cp result.json s3://$RESULTS_BUCKET/$RESULT_FILE
              aws s3 cp test-results.xml s3://$RESULTS_BUCKET/results/$STUDENT_ID/$TIMESTAMP/ || true
              aws s3 cp test-output.txt s3://$RESULTS_BUCKET/results/$STUDENT_ID/$TIMESTAMP/ || true
              aws s3 cp lint-output.txt s3://$RESULTS_BUCKET/results/$STUDENT_ID/$TIMESTAMP/ || true
            - echo "Autograding completed"
      artifacts:
        files:
          - '**/*'
    EOT
  }

  source_version = "main"

  tags = {
    Name = "${var.project_name}-project"
  }
}

# SNS topic for autograder notifications
resource "aws_sns_topic" "autograder_notifications" {
  name = "${var.project_name}-notifications"

  tags = {
    Name = "${var.project_name}-notifications"
  }
}

# CloudWatch Event Rule to trigger on CodeBuild state changes
resource "aws_cloudwatch_event_rule" "codebuild_state_change" {
  name        = "${var.project_name}-build-state-change"
  description = "Trigger on CodeBuild state changes"

  event_pattern = jsonencode({
    source      = ["aws.codebuild"]
    detail-type = ["CodeBuild Build State Change"]
    detail = {
      project-name = [aws_codebuild_project.autograder.name]
      build-status = ["SUCCEEDED", "FAILED", "STOPPED"]
    }
  })

  tags = {
    Name = "${var.project_name}-event-rule"
  }
}

resource "aws_cloudwatch_event_target" "sns" {
  rule      = aws_cloudwatch_event_rule.codebuild_state_change.name
  target_id = "SendToSNS"
  arn       = aws_sns_topic.autograder_notifications.arn
}

resource "aws_sns_topic_policy" "autograder_notifications" {
  arn = aws_sns_topic.autograder_notifications.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "events.amazonaws.com"
        }
        Action   = "SNS:Publish"
        Resource = aws_sns_topic.autograder_notifications.arn
      }
    ]
  })
}

# DynamoDB table for tracking submission metadata
resource "aws_dynamodb_table" "submissions" {
  name           = "${var.project_name}-submissions"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "student_id"
  range_key      = "timestamp"

  attribute {
    name = "student_id"
    type = "S"
  }

  attribute {
    name = "timestamp"
    type = "S"
  }

  attribute {
    name = "assignment_id"
    type = "S"
  }

  global_secondary_index {
    name            = "assignment-index"
    hash_key        = "assignment_id"
    range_key       = "timestamp"
    projection_type = "ALL"
  }

  tags = {
    Name = "${var.project_name}-submissions"
  }
}

# IAM policy for DynamoDB access from CodeBuild
resource "aws_iam_role_policy" "codebuild_dynamodb_policy" {
  name = "${var.project_name}-codebuild-dynamodb-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem",
          "dynamodb:GetItem",
          "dynamodb:Query",
          "dynamodb:UpdateItem"
        ]
        Resource = [
          aws_dynamodb_table.submissions.arn,
          "${aws_dynamodb_table.submissions.arn}/index/*"
        ]
      }
    ]
  })
}

data "aws_caller_identity" "current" {}

output "results_bucket_name" {
  description = "S3 bucket name for autograder results"
  value       = aws_s3_bucket.autograder_results.bucket
}

output "artifacts_bucket_name" {
  description = "S3 bucket name for CodeBuild artifacts"
  value       = aws_s3_bucket.codebuild_artifacts.bucket
}

output "codebuild_project_name" {
  description = "CodeBuild project name"
  value       = aws_codebuild_project.autograder.name
}

output "sns_topic_arn" {
  description = "SNS topic ARN for notifications"
  value       = aws_sns_topic.autograder_notifications.arn
}

output "dynamodb_table_name" {
  description = "DynamoDB table name for submission tracking"
  value       = aws_dynamodb_table.submissions.name
}

output "cloudwatch_log_group" {
  description = "CloudWatch log group for CodeBuild logs"
  value       = aws_cloudwatch_log_group.codebuild_logs.name
}
