    Name        = "Autograder Logs"
    Environment = "production"
  }
}

# CodeBuild Project for Autograder
resource "aws_codebuild_project" "autograder" {
  name          = "cs-class-autograder"
  description   = "Autograder for CS class assignments"
  build_timeout = 60
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  cache {
    type     = "S3"
    location = aws_s3_bucket.autograder_artifacts.bucket
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                      = "aws/codebuild/standard:7.0"
    type                       = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode            = false

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.id
    }

    environment_variable {
      name  = "STUDENT_REPO_URL"
      value = "https://github.com/your-org/student-submissions"
      type  = "PLAINTEXT"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.autograder_logs.name
      stream_name = "build-log"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-submissions.git"
    git_clone_depth = 1
    buildspec       = <<-EOF
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.11
        pre_build:
          commands:
            - echo "Starting autograder..."
            - export SUBMISSION_ID=$(echo $CODEBUILD_RESOLVED_SOURCE_VERSION | cut -c1-8)
            - export TIMESTAMP=$(date +%Y%m%d-%H%M%S)
        build:
          commands:
            - echo "Running student code..."
            - echo "Add your test commands here"
            - echo "Example: python -m pytest tests/ --junitxml=results.xml"
        post_build:
          commands:
            - echo "Uploading results to S3..."
            - |
              cat > results.json <<RESULT
              {
                "submission_id": "$SUBMISSION_ID",
                "timestamp": "$TIMESTAMP",
                "status": "completed",
                "build_id": "$CODEBUILD_BUILD_ID"
              }
              RESULT
            - aws s3 cp results.json s3://$RESULTS_BUCKET/$SUBMISSION_ID-$TIMESTAMP-results.json
            - echo "Autograder completed successfully"
      EOF
  }

  tags = {
    Name        = "CS Class Autograder"
    Environment = "production"
  }
}

# SNS Topic for build notifications (optional)
resource "aws_sns_topic" "autograder_notifications" {
  name = "cs-class-autograder-notifications"

  tags = {
    Name        = "Autograder Notifications"
    Environment = "production"
  }
}

# EventBridge Rule for CodeBuild state changes
resource "aws_cloudwatch_event_rule" "codebuild_state_change" {
  name        = "cs-class-autograder-state-change"
  description = "Trigger on CodeBuild state changes"

  event_pattern = jsonencode({
    source      = ["aws.codebuild"]
    detail-type = ["CodeBuild Build State Change"]
    detail = {
      project-name = [aws_codebuild_project.autograder.name]
    }
  })
}

resource "aws_cloudwatch_event_target" "sns_target" {
  rule      = aws_cloudwatch_event_rule.codebuild_state_change.name
  target_id = "SendToSNS"
  arn       = aws_sns_topic.autograder_notifications.arn
}

resource "aws_sns_topic_policy" "autograder_notifications_policy" {
  arn = aws_sns_topic.autograder_notifications.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "events.amazonaws.com"
        }
        Action   = "SNS:Publish"
        Resource = aws_sns_topic.autograder_notifications.arn
      }
    ]
  })
}

