  description = "S3 bucket name for autograder results"
  value       = aws_s3_bucket.autograder_results.id
}

output "artifacts_bucket_name" {
  description = "S3 bucket name for autograder artifacts"
  value       = aws_s3_bucket.autograder_artifacts.id
}

output "codebuild_project_name" {
