  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "${var.project_name}-private-subnet-1"
  }
}

resource "aws_subnet" "private_subnet_2" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]

  tags = {
    Name = "${var.project_name}-private-subnet-2"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Route Table for private subnets - No internet route
resource "aws_route_table" "private_rt" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "${var.project_name}-private-rt"
  }
}

resource "aws_route_table_association" "private_rta_1" {
  subnet_id      = aws_subnet.private_subnet_1.id
  route_table_id = aws_route_table.private_rt.id
}

resource "aws_route_table_association" "private_rta_2" {
  subnet_id      = aws_subnet.private_subnet_2.id
  route_table_id = aws_route_table.private_rt.id
}

# VPC Endpoints for AWS services (CodeBuild, S3, Secrets Manager, CloudWatch Logs)
resource "aws_vpc_endpoint" "s3" {
  vpc_id            = aws_vpc.autograder_vpc.id
  service_name      = "com.amazonaws.${var.aws_region}.s3"
  vpc_endpoint_type = "Gateway"
  route_table_ids   = [aws_route_table.private_rt.id]

  tags = {
    Name = "${var.project_name}-s3-endpoint"
  }
}

resource "aws_security_group" "vpc_endpoints_sg" {
  name        = "${var.project_name}-vpc-endpoints-sg"
  description = "Security group for VPC endpoints"
  vpc_id      = aws_vpc.autograder_vpc.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }

  tags = {
    Name = "${var.project_name}-vpc-endpoints-sg"
  }
}

resource "aws_vpc_endpoint" "logs" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${var.aws_region}.logs"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
  security_group_ids  = [aws_security_group.vpc_endpoints_sg.id]
  private_dns_enabled = true

  tags = {
    Name = "${var.project_name}-logs-endpoint"
  }
}

resource "aws_vpc_endpoint" "secretsmanager" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${var.aws_region}.secretsmanager"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
  security_group_ids  = [aws_security_group.vpc_endpoints_sg.id]
  private_dns_enabled = true

  tags = {
    Name = "${var.project_name}-secretsmanager-endpoint"
  }
}

# Security Group for CodeBuild - No outbound internet access
resource "aws_security_group" "codebuild_sg" {
  name        = "${var.project_name}-codebuild-sg"
  description = "Security group for CodeBuild - blocks internet access"
  vpc_id      = aws_vpc.autograder_vpc.id

  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
    description = "Allow HTTPS to VPC endpoints only"
  }

  tags = {
    Name = "${var.project_name}-codebuild-sg"
  }
}

# S3 Bucket for autograder results
resource "aws_s3_bucket" "autograder_results" {
  bucket = "${var.project_name}-results-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name = "${var.project_name}-results"
  }
}

resource "aws_s3_bucket_versioning" "autograder_results_versioning" {
  bucket = aws_s3_bucket.autograder_results.id

  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "autograder_results_encryption" {
  bucket = aws_s3_bucket.autograder_results.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "autograder_results_block" {
  bucket = aws_s3_bucket.autograder_results.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# S3 Bucket for CodeBuild cache
resource "aws_s3_bucket" "codebuild_cache" {
  bucket = "${var.project_name}-cache-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name = "${var.project_name}-cache"
  }
}

resource "aws_s3_bucket_public_access_block" "codebuild_cache_block" {
  bucket = aws_s3_bucket.codebuild_cache.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "${var.project_name}-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "${var.project_name}-codebuild-role"
  }
}

resource "aws_iam_role_policy" "codebuild_policy" {
  name = "${var.project_name}-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = [
          "arn:aws:logs:${var.aws_region}:${data.aws_caller_identity.current.account_id}:log-group:/aws/codebuild/${var.project_name}*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetObjectVersion"
        ]
        Resource = [
          "${aws_s3_bucket.autograder_results.arn}/*",
          "${aws_s3_bucket.codebuild_cache.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          aws_s3_bucket.codebuild_cache.arn
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue"
        ]
        Resource = "arn:aws:secretsmanager:${var.aws_region}:${data.aws_caller_identity.current.account_id}:secret:${var.github_token_secret_name}*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeVpcs",
          "ec2:CreateNetworkInterfacePermission"
        ]
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/${var.project_name}"
  retention_in_days = 30

  tags = {
    Name = "${var.project_name}-logs"
  }
}

# CodeBuild Project for Autograding
resource "aws_codebuild_project" "autograder" {
  name          = var.project_name
  description   = "Autograder for CS class - runs in isolated VPC"
  build_timeout = "60"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  cache {
    type     = "S3"
    location = aws_s3_bucket.codebuild_cache.bucket
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.id
    }

    environment_variable {
      name  = "GITHUB_TOKEN"
      value = var.github_token_secret_name
      type  = "SECRETS_MANAGER"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name = aws_cloudwatch_log_group.codebuild_logs.name
      status     = "ENABLED"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-submissions.git"
    git_clone_depth = 1
    buildspec       = <<-EOT
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.11
          commands:
            - echo "Installing test dependencies..."
        pre_build:
          commands:
            - echo "Setting up test environment..."
            - echo "Student code is isolated from internet access"
        build:
          commands:
            - echo "Running autograder tests..."
            - echo "Add your test commands here"
            - python -m pytest tests/ --junitxml=results.xml || true
        post_build:
          commands:
            - echo "Uploading results to S3..."
            - TIMESTAMP=$(date +%Y%m%d-%H%M%S)
            - STUDENT_ID=$${CODEBUILD_INITIATOR##*/}
            - aws s3 cp results.xml s3://$RESULTS_BUCKET/$STUDENT_ID/$TIMESTAMP/results.xml
            - echo "Results uploaded successfully"
      artifacts:
        files:
          - results.xml
    EOT
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  tags = {
    Name = var.project_name
  }
}

data "aws_caller_identity" "current" {}

# Outputs
output "codebuild_project_name" {
  description = "Name of the CodeBuild project"
  value       = aws_codebuild_project.autograder.name
}

output "results_bucket_name" {
  description = "S3 bucket for autograder results"
  value       = aws_s3_bucket.autograder_results.id
}

output "vpc_id" {
  description = "VPC ID for the isolated autograder environment"
  value       = aws_vpc.autograder_vpc.id
}

output "github_token_secret_name" {
  description = "Name of the Secrets Manager secret for GitHub token (must be created manually)"
  value       = var.github_token_secret_name
}

output "instructions" {
  description = "Setup instructions"
  value       = <<-EOT
    Next steps:
    1. Create GitHub personal access token in AWS Secrets Manager with name: ${var.github_token_secret_name}
    2. Update the GitHub repository URL in the CodeBuild source configuration
    3. Customize the buildspec to match your grading requirements
    4. Start builds via AWS Console, CLI, or trigger via webhooks

    Note: Students' code runs in an isolated VPC with NO internet access.
  EOT
}
```

