```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "github_token" {
  description = "GitHub personal access token for CodeBuild"
  type        = string
  sensitive   = true
}

# VPC for isolated autograding environment
resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

# Private subnet for CodeBuild (no internet access)
resource "aws_subnet" "private_subnet_1" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "autograder-private-subnet-1"
  }
}

resource "aws_subnet" "private_subnet_2" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]

  tags = {
    Name = "autograder-private-subnet-2"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# VPC Endpoint for S3 (allows S3 access without internet)
resource "aws_vpc_endpoint" "s3" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.${var.aws_region}.s3"

  tags = {
    Name = "autograder-s3-endpoint"
  }
}

# Route table for private subnets
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "autograder-private-rt"
  }
}

resource "aws_route_table_association" "private_1" {
  subnet_id      = aws_subnet.private_subnet_1.id
  route_table_id = aws_route_table.private.id
}

resource "aws_route_table_association" "private_2" {
  subnet_id      = aws_subnet.private_subnet_2.id
  route_table_id = aws_route_table.private.id
}

# Associate S3 endpoint with route table
resource "aws_vpc_endpoint_route_table_association" "s3" {
  route_table_id  = aws_route_table.private.id
  vpc_endpoint_id = aws_vpc_endpoint.s3.id
}

# Security group for CodeBuild - no outbound internet access
resource "aws_security_group" "codebuild_sg" {
  name        = "autograder-codebuild-sg"
  description = "Security group for autograder CodeBuild - blocks internet access"
  vpc_id      = aws_vpc.autograder_vpc.id

  # Allow outbound only to VPC endpoints (S3)
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
    description = "HTTPS to VPC endpoints only"
  }

  tags = {
    Name = "autograder-codebuild-sg"
  }
}

# VPC Endpoint for CodeBuild (allows CodeBuild API access without internet)
resource "aws_vpc_endpoint" "codebuild" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${var.aws_region}.codebuild"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
  security_group_ids  = [aws_security_group.vpc_endpoints.id]
  private_dns_enabled = true

  tags = {
    Name = "autograder-codebuild-endpoint"
  }
}

# VPC Endpoint for Logs (allows CloudWatch Logs access without internet)
resource "aws_vpc_endpoint" "logs" {
  vpc_id              = aws_vpc.autograder_vpc.id
  service_name        = "com.amazonaws.${var.aws_region}.logs"
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
  security_group_ids  = [aws_security_group.vpc_endpoints.id]
  private_dns_enabled = true

  tags = {
    Name = "autograder-logs-endpoint"
  }
}

# Security group for VPC endpoints
resource "aws_security_group" "vpc_endpoints" {
  name        = "autograder-vpc-endpoints-sg"
  description = "Security group for VPC endpoints"
  vpc_id      = aws_vpc.autograder_vpc.id

  ingress {
    from_port       = 443
    to_port         = 443
    protocol        = "tcp"
    security_groups = [aws_security_group.codebuild_sg.id]
    description     = "HTTPS from CodeBuild"
  }

  tags = {
    Name = "autograder-vpc-endpoints-sg"
  }
}

# S3 bucket for storing autograding results
resource "aws_s3_bucket" "autograder_results" {
  bucket = "autograder-results-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name = "autograder-results"
  }
}

resource "aws_s3_bucket_versioning" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id

  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_public_access_block" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# S3 bucket for CodeBuild artifacts and cache
resource "aws_s3_bucket" "codebuild_artifacts" {
  bucket = "autograder-codebuild-artifacts-${data.aws_caller_identity.current.account_id}"

  tags = {
    Name = "autograder-codebuild-artifacts"
  }
}

resource "aws_s3_bucket_public_access_block" "codebuild_artifacts" {
  bucket = aws_s3_bucket.codebuild_artifacts.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

data "aws_caller_identity" "current" {}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for CodeBuild
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.id
  name = "autograder-codebuild-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = [
          "arn:aws:logs:${var.aws_region}:${data.aws_caller_identity.current.account_id}:log-group:/aws/codebuild/autograder-*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Resource = [
          "${aws_s3_bucket.autograder_results.arn}/*",
          "${aws_s3_bucket.codebuild_artifacts.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          aws_s3_bucket.codebuild_artifacts.arn
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeVpcs",
          "ec2:CreateNetworkInterfacePermission"
        ]
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/autograder-project"
  retention_in_days = 30

  tags = {
    Name = "autograder-codebuild-logs"
  }
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project"
  description   = "Autograder for CS class assignments"
  build_timeout = 60
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.codebuild_artifacts.bucket
    path = "artifacts"
    packaging = "ZIP"
  }

  cache {
    type     = "S3"
    location = "${aws_s3_bucket.codebuild_artifacts.bucket}/cache"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.bucket
    }

    environment_variable {
      name  = "AWS_REGION"
      value = var.aws_region
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.codebuild_logs.name
      stream_name = "build-log"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-submissions.git"
    git_clone_depth = 1
    buildspec       = file("${path.module}/buildspec.yml")
  }

  vpc_config {
    vpc_id = aws_vpc.autograder_vpc.id
    subnets = [
      aws_subnet.private_subnet_1.id,
      aws_subnet.private_subnet_2.id
    ]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  tags = {
    Name = "autograder-project"
  }
}

# GitHub source credentials for CodeBuild
resource "aws_codebuild_source_credential" "github" {
  auth_type   = "PERSONAL_ACCESS_TOKEN"
  server_type = "GITHUB"
  token       = var.github_token
}

# Lambda execution role for triggering CodeBuild
resource "aws_iam_role" "lambda_trigger_role" {
  name = "autograder-lambda-trigger-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_trigger_policy" {
  role = aws_iam_role.lambda_trigger_role.id
  name = "autograder-lambda-trigger-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:${var.aws_region}:${data.aws_caller_identity.current.account_id}:*"
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:StartBuild"
        ]
        Resource = aws_codebuild_project.autograder.arn
      }
    ]
  })
}

# Lambda function to trigger CodeBuild (example trigger mechanism)
resource "aws_lambda_function" "trigger_autograder" {
  filename      = "lambda_function.zip"
  function_name = "autograder-trigger"
  role          = aws_iam_role.lambda_trigger_role.arn
  handler       = "index.handler"
  runtime       = "python3.11"
  timeout       = 30

  environment {
    variables = {
      CODEBUILD_PROJECT = aws_codebuild_project.autograder.name
    }
  }

  tags = {
    Name = "autograder-trigger"
  }
}

# CloudWatch Log Group for Lambda
resource "aws_cloudwatch_log_group" "lambda_logs" {
  name              = "/aws/lambda/${aws_lambda_function.trigger_autograder.function_name}"
  retention_in_days = 14

  tags = {
    Name = "autograder-lambda-logs"
  }
}

# Outputs
output "results_bucket_name" {
  description = "S3 bucket name for autograding results"
  value       = aws_s3_bucket.autograder_results.bucket
}

output "codebuild_project_name" {
  description = "CodeBuild project name"
  value       = aws_codebuild_project.autograder.name
}

output "vpc_id" {
  description = "VPC ID for autograder environment"
  value       = aws_vpc.autograder_vpc.id
}

output "lambda_function_name" {
  description = "Lambda function name for triggering autograder"
  value       = aws_lambda_function.trigger_autograder.function_name
}
```

