# Lambda function for uploading cat pictures
data "archive_file" "upload_lambda" {
  type        = "zip"
  output_path = "${path.module}/upload_lambda.zip"

  source {
    content  = <<EOF
import json
import boto3
import base64
import uuid
import time
import os

s3 = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')

def lambda_handler(event, context):
    try:
        body = json.loads(event['body'])
        image_data = base64.b64decode(body['image'])

        picture_id = str(uuid.uuid4())
        bucket_name = os.environ['BUCKET_NAME']
        table_name = os.environ['TABLE_NAME']

        s3.put_object(
            Bucket=bucket_name,
            Key=f"cats/{picture_id}.jpg",
            Body=image_data,
            ContentType='image/jpeg'
        )

        table = dynamodb.Table(table_name)
        table.put_item(
            Item={
                'pictureId': picture_id,
                'uploadTimestamp': int(time.time()),
                's3Key': f"cats/{picture_id}.jpg"
            }
        )

        return {
            'statusCode': 200,
            'headers': {
                'Access-Control-Allow-Origin': '*',
                'Content-Type': 'application/json'
            },
            'body': json.dumps({
                'message': 'Cat picture uploaded successfully',
                'pictureId': picture_id
            })
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {
                'Access-Control-Allow-Origin': '*',
                'Content-Type': 'application/json'
            },
            'body': json.dumps({'error': str(e)})
        }
EOF
    filename = "lambda_function.py"
  }
}

