data "archive_file" "get_random_lambda" {
  type        = "zip"
  output_path = "${path.module}/get_random_lambda.zip"

  source {
    content  = <<EOF
import json
import boto3
import random
import os

s3 = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')

def lambda_handler(event, context):
    try:
        table_name = os.environ['TABLE_NAME']
        bucket_name = os.environ['BUCKET_NAME']

        table = dynamodb.Table(table_name)
        response = table.scan()

        if not response['Items']:
            return {
                'statusCode': 404,
                'headers': {
                    'Access-Control-Allow-Origin': '*',
                    'Content-Type': 'application/json'
                },
                'body': json.dumps({'message': 'No cat pictures found'})
            }

        random_item = random.choice(response['Items'])
        s3_key = random_item['s3Key']

        presigned_url = s3.generate_presigned_url(
            'get_object',
            Params={'Bucket': bucket_name, 'Key': s3_key},
            ExpiresIn=3600
        )

        return {
            'statusCode': 200,
            'headers': {
                'Access-Control-Allow-Origin': '*',
                'Content-Type': 'application/json'
            },
            'body': json.dumps({
                'pictureId': random_item['pictureId'],
                'url': presigned_url
            })
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {
                'Access-Control-Allow-Origin': '*',
                'Content-Type': 'application/json'
            },
            'body': json.dumps({'error': str(e)})
        }
EOF
    filename = "lambda_function.py"
  }
}

