  name              = "/aws/lambda/${aws_lambda_function.daily_function.function_name}"
  retention_in_days = 7
}

# EventBridge Rule to trigger Lambda at 7 UTC daily
resource "aws_cloudwatch_event_rule" "daily_trigger" {
  name                = "daily-7am-utc-trigger"
  description         = "Trigger Lambda function every day at 7 UTC"
  schedule_expression = "cron(0 7 * * ? *)"
}

