terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Lightsail Bucket
resource "aws_lightsail_bucket" "main" {
  name      = "my-lightsail-bucket"
  bundle_id = "small_1_0"
}

# Lightsail Bucket Access Key
resource "aws_lightsail_bucket_access_key" "main" {
  bucket_name = aws_lightsail_bucket.main.name
}

# Lightsail Distribution
resource "aws_lightsail_distribution" "main" {
  name      = "my-lightsail-distribution"
  bundle_id = "small_1_0"

  origin {
    name          = aws_lightsail_bucket.main.name
    region_name   = aws_lightsail_bucket.main.region
    protocol_policy = "http-only"
  }

  default_cache_behavior {
    behavior = "cache"
  }

  cache_behavior_settings {
    allowed_http_methods = "GET,HEAD,OPTIONS,PUT,PATCH,POST,DELETE"
    cached_http_methods  = "GET,HEAD"
    default_ttl          = 86400
    maximum_ttl          = 31536000
    minimum_ttl          = 0

    forwarded_cookies {
      option = "none"
    }

    forwarded_headers {
      option = "default"
    }

    forwarded_query_strings {
      option = false
    }
  }

  is_enabled = true

  tags = {
    Name        = "my-lightsail-distribution"
    Environment = "production"
  }
}

# Outputs
output "bucket_name" {
  value       = aws_lightsail_bucket.main.name
  description = "Name of the Lightsail bucket"
}

output "bucket_url" {
  value       = aws_lightsail_bucket.main.url
  description = "URL of the Lightsail bucket"
}

output "distribution_domain_name" {
  value       = aws_lightsail_distribution.main.domain_name
  description = "Domain name of the Lightsail distribution"
}

output "distribution_status" {
  value       = aws_lightsail_distribution.main.status
  description = "Status of the Lightsail distribution"
}

