provider "aws" {
  region = "us-east-1"
}

# Lightsail Instance
resource "aws_lightsail_instance" "origin" {
  name              = "my-lightsail-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "wordpress"
  bundle_id         = "micro_2_0"

  tags = {
    Name = "Origin Instance"
  }
}

# Lightsail Static IP
resource "aws_lightsail_static_ip" "origin_ip" {
  name = "my-lightsail-static-ip"
}

# Attach Static IP to Instance
resource "aws_lightsail_static_ip_attachment" "origin_ip_attachment" {
  static_ip_name = aws_lightsail_static_ip.origin_ip.id
  instance_name  = aws_lightsail_instance.origin.id
}

# Lightsail Distribution
resource "aws_lightsail_distribution" "cdn" {
  name      = "my-lightsail-distribution"
  bundle_id = "small_1_0"

  origin {
    name          = aws_lightsail_instance.origin.name
    region_name   = aws_lightsail_instance.origin.availability_zone
    protocol_policy = "http-only"
  }

  default_cache_behavior {
    behavior = "cache"
  }

  cache_behavior_settings {
    default_ttl = 86400
    maximum_ttl = 31536000
    minimum_ttl = 0

    allowed_http_methods = "GET,HEAD,OPTIONS,PUT,PATCH,POST,DELETE"
    cached_http_methods  = "GET,HEAD"

    forwarded_cookies {
      option = "none"
    }

    forwarded_headers {
      option = "default"
    }

    forwarded_query_strings {
      option = false
    }
  }

  cache_behavior {
    behavior = "dont-cache"
    path     = "/admin/*"
  }

  tags = {
    Name = "Lightsail Distribution"
  }
}

output "instance_public_ip" {
  value       = aws_lightsail_static_ip.origin_ip.ip_address
  description = "Public IP of the Lightsail instance"
}

output "distribution_domain" {
  value       = aws_lightsail_distribution.cdn.domain_name
  description = "Domain name of the Lightsail distribution"
}
