terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "aws_glacier_vault" "archive_vault" {
  name = "long-term-archive-vault"

  notification {
    sns_topic = aws_sns_topic.glacier_notifications.arn
    events    = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
  }

  access_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowCurrentAccount"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action = [
          "glacier:DeleteArchive",
          "glacier:InitiateJob",
          "glacier:UploadArchive"
        ]
        Resource = "arn:aws:glacier:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:vaults/long-term-archive-vault"
      }
    ]
  })

  tags = {
    Name        = "Long Term Archive Vault"
    Environment = "production"
    Purpose     = "data-archival"
  }
}

resource "aws_glacier_vault_lock" "vault_lock" {
  vault_name         = aws_glacier_vault.archive_vault.name
  complete_lock      = false
  ignore_deletion_error = false

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "DenyDeletion"
        Effect = "Deny"
        Principal = {
          AWS = "*"
        }
        Action   = "glacier:DeleteArchive"
        Resource = aws_glacier_vault.archive_vault.arn
        Condition = {
          NumericLessThan = {
            "glacier:ArchiveAgeInDays" = "365"
          }
        }
      }
    ]
  })
}

resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-vault-notifications"

  tags = {
    Name        = "Glacier Notifications"
    Environment = "production"
  }
}

resource "aws_sns_topic_subscription" "glacier_notifications_email" {
  topic_arn = aws_sns_topic.glacier_notifications.arn
  protocol  = "email"
  endpoint  = "admin@example.com"
}

data "aws_caller_identity" "current" {}

data "aws_region" "current" {}

output "vault_arn" {
  description = "ARN of the Glacier vault"
  value       = aws_glacier_vault.archive_vault.arn
}

output "vault_name" {
  description = "Name of the Glacier vault"
  value       = aws_glacier_vault.archive_vault.name
}

output "sns_topic_arn" {
  description = "ARN of the SNS topic for notifications"
  value       = aws_sns_topic.glacier_notifications.arn
}

