extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  description = "AWS region for resources"
  type        = string
  default     = "us-east-1"
}

variable "project_name" {
  description = "Project name for resource naming"
  type        = string
  default     = "long-term-storage"
}

variable "environment" {
  description = "Environment name"
  type        = string
  default     = "production"
}

# S3 Bucket for long-term storage and backups
resource "aws_s3_bucket" "long_term_storage" {
  bucket = "${var.project_name}-backup-${var.environment}"

  tags = {
    Name        = "${var.project_name}-backup"
    Environment = var.environment
    Purpose     = "Long-term data storage and backup"
  }
}

# Enable versioning for backup protection
resource "aws_s3_bucket_versioning" "long_term_storage" {
  bucket = aws_s3_bucket.long_term_storage.id

  versioning_configuration {
    status = "Enabled"
  }
}

# Server-side encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "long_term_storage" {
  bucket = aws_s3_bucket.long_term_storage.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# Block public access
resource "aws_s3_bucket_public_access_block" "long_term_storage" {
  bucket = aws_s3_bucket.long_term_storage.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Lifecycle policy for cost optimization
resource "aws_s3_bucket_lifecycle_configuration" "long_term_storage" {
  bucket = aws_s3_bucket.long_term_storage.id

  rule {
    id     = "transition-to-glacier"
    status = "Enabled"

    transition {
      days          = 90
      storage_class = "GLACIER"
    }

    transition {
      days          = 180
      storage_class = "DEEP_ARCHIVE"
    }

    noncurrent_version_transition {
      noncurrent_days = 30
      storage_class   = "GLACIER"
    }

    noncurrent_version_expiration {
      noncurrent_days = 365
    }
  }
}

# S3 Bucket for immediate backups (Standard storage)
resource "aws_s3_bucket" "backup_standard" {
  bucket = "${var.project_name}-backup-standard-${var.environment}"

  tags = {
    Name        = "${var.project_name}-backup-standard"
    Environment = var.environment
    Purpose     = "Recent backups with frequent access"
  }
}

resource "aws_s3_bucket_versioning" "backup_standard" {
  bucket = aws_s3_bucket.backup_standard.id

  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "backup_standard" {
  bucket = aws_s3_bucket.backup_standard.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "backup_standard" {
  bucket = aws_s3_bucket.backup_standard.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Lifecycle policy for standard backup bucket
resource "aws_s3_bucket_lifecycle_configuration" "backup_standard" {
  bucket = aws_s3_bucket.backup_standard.id

  rule {
    id     = "expire-old-backups"
    status = "Enabled"

    expiration {
      days = 30
    }

    noncurrent_version_expiration {
      noncurrent_days = 7
    }
  }
}

# EFS for shared file storage backup
resource "aws_efs_file_system" "backup_efs" {
  creation_token = "${var.project_name}-efs-backup"
  encrypted      = true

  lifecycle_policy {
    transition_to_ia = "AFTER_30_DAYS"
  }

  lifecycle_policy {
    transition_to_archive = "AFTER_90_DAYS"
  }

  tags = {
    Name        = "${var.project_name}-efs-backup"
    Environment = var.environment
    Purpose     = "Long-term file storage backup"
  }
}

# Backup Vault for AWS Backup service
resource "aws_backup_vault" "main" {
  name = "${var.project_name}-backup-vault"

  tags = {
    Name        = "${var.project_name}-backup-vault"
    Environment = var.environment
  }
}

# Backup plan
resource "aws_backup_plan" "main" {
  name = "${var.project_name}-backup-plan"

  rule {
    rule_name         = "daily_backup"
    target_vault_name = aws_backup_vault.main.name
    schedule          = "cron(0 2 * * ? *)"

    lifecycle {
      delete_after = 365
      cold_storage_after = 90
    }
  }

  rule {
    rule_name         = "weekly_backup"
    target_vault_name = aws_backup_vault.main.name
    schedule          = "cron(0 3 ? * 1 *)"

    lifecycle {
      delete_after = 2555
      cold_storage_after = 180
    }
  }

  tags = {
    Name        = "${var.project_name}-backup-plan"
    Environment = var.environment
  }
}

# Outputs
output "long_term_storage_bucket_name" {
  description = "Name of the long-term storage S3 bucket"
  value       = aws_s3_bucket.long_term_storage.id
}

output "long_term_storage_bucket_arn" {
  description = "ARN of the long-term storage S3 bucket"
  value       = aws_s3_bucket.long_term_storage.arn
}

output "backup_standard_bucket_name" {
  description = "Name of the standard backup S3 bucket"
  value       = aws_s3_bucket.backup_standard.id
}

output "backup_standard_bucket_arn" {
  description = "ARN of the standard backup S3 bucket"
  value       = aws_s3_bucket.backup_standard.arn
}

output "efs_id" {
  description = "ID of the EFS file system"
  value       = aws_efs_file_system.backup_efs.id
}

output "backup_vault_name" {
  description = "Name of the AWS Backup vault"
  value       = aws_backup_vault.main.name
}

output "backup_vault_arn" {
  description = "ARN of the AWS Backup vault"
  value       = aws_backup_vault.main.arn
}

