provider "aws" {
  region = "us-east-1"
}

# Glacier Vault
resource "aws_glacier_vault" "main" {
  name = "my-glacier-vault"

  tags = {
    Name        = "My Glacier Vault"
    Environment = "production"
  }
}

# Glacier Vault Notification Configuration (Optional)
resource "aws_glacier_vault_notification" "main" {
  vault_name = aws_glacier_vault.main.name

  sns_topic = aws_sns_topic.glacier_notifications.arn

  events = [
    "ArchiveRetrievalCompleted",
    "InventoryRetrievalCompleted"
  ]
}

# SNS Topic for Glacier notifications
resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-vault-notifications"

  tags = {
    Name = "Glacier Vault Notifications"
  }
}

# IAM Role for DLM
resource "aws_iam_role" "dlm_lifecycle_role" {
  name = "dlm-lifecycle-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dlm.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "DLM Lifecycle Role"
  }
}

# IAM Policy for DLM
resource "aws_iam_role_policy" "dlm_lifecycle_policy" {
  name = "dlm-lifecycle-policy"
  role = aws_iam_role.dlm_lifecycle_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateSnapshot",
          "ec2:CreateSnapshots",
          "ec2:DeleteSnapshot",
          "ec2:DescribeInstances",
          "ec2:DescribeVolumes",
          "ec2:DescribeSnapshots",
          "ec2:EnableFastSnapshotRestores",
          "ec2:DescribeFastSnapshotRestores",
          "ec2:DisableFastSnapshotRestores",
          "ec2:CopySnapshot",
          "ec2:ModifySnapshotAttribute",
          "ec2:DescribeSnapshotAttribute"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateTags"
        ]
        Resource = "arn:aws:ec2:*::snapshot/*"
      }
    ]
  })
}

# DLM Lifecycle Policy for EBS snapshots with archiving to Glacier
resource "aws_dlm_lifecycle_policy" "ebs_snapshot_policy" {
  description        = "DLM policy for EBS snapshots with Glacier archival"
  execution_role_arn = aws_iam_role.dlm_lifecycle_role.arn
  state              = "ENABLED"

  policy_details {
    resource_types = ["VOLUME"]

    schedule {
      name = "Daily snapshots with Glacier archival"

      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["03:00"]
      }

      retain_rule {
        count = 30
      }

      tags_to_add = {
        SnapshotCreator = "DLM"
        Lifecycle       = "Managed"
      }

      copy_tags = true

      # Archive snapshots to Glacier after 7 days
      deprecate_rule {
        interval      = 7
        interval_unit = "DAYS"
      }

      # Archive tier configuration
      archive_rule {
        retain_rule {
          retention_archive_tier {
            count = 90
            interval_unit = "DAYS"
          }
        }
      }
    }

    target_tags = {
      Backup = "true"
    }

    parameters {
      exclude_boot_volume = false
    }
  }

  tags = {
    Name        = "EBS-Snapshot-DLM-Policy"
    Environment = "production"
  }
}

# Example EBS Volume with tags for DLM targeting
resource "aws_ebs_volume" "example" {
  availability_zone = "us-east-1a"
  size              = 10
  type              = "gp3"

  tags = {
    Name   = "Example Volume"
    Backup = "true"
  }
}

# Outputs
output "glacier_vault_arn" {
  description = "ARN of the Glacier vault"
  value       = aws_glacier_vault.main.arn
}

output "glacier_vault_name" {
  description = "Name of the Glacier vault"
  value       = aws_glacier_vault.main.name
}

output "dlm_policy_id" {
  description = "ID of the DLM lifecycle policy"
  value       = aws_dlm_lifecycle_policy.ebs_snapshot_policy.id
}

output "dlm_policy_arn" {
  description = "ARN of the DLM lifecycle policy"
  value       = aws_dlm_lifecycle_policy.ebs_snapshot_policy.arn
}

