provider "aws" {
  region = "us-east-1"
}

# SNS Topic for Glacier notifications
resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-archive-retrieval-notifications"
}

# SNS Topic Policy to allow Glacier to publish
resource "aws_sns_topic_policy" "glacier_notifications_policy" {
  arn = aws_sns_topic.glacier_notifications.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowGlacierPublish"
        Effect = "Allow"
        Principal = {
          Service = "glacier.amazonaws.com"
        }
        Action   = "SNS:Publish"
        Resource = aws_sns_topic.glacier_notifications.arn
      }
    ]
  })
}

# Glacier Vault
resource "aws_glacier_vault" "main" {
  name = "archive-vault"

  notification {
    sns_topic = aws_sns_topic.glacier_notifications.arn
    events    = ["ArchiveRetrievalCompleted"]
  }

  tags = {
    Name        = "archive-vault"
    Environment = "production"
  }
}

# Optional: SNS Email Subscription (replace with your email)
resource "aws_sns_topic_subscription" "email_subscription" {
  topic_arn = aws_sns_topic.glacier_notifications.arn
  protocol  = "email"
  endpoint  = "your-email@example.com"
}

output "vault_arn" {
  value       = aws_glacier_vault.main.arn
  description = "ARN of the Glacier vault"
}

output "sns_topic_arn" {
  value       = aws_sns_topic.glacier_notifications.arn
  description = "ARN of the SNS topic for notifications"
}

