provider "aws" {
  region = "us-east-1"
}

# VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "gwlb-vpc"
  }
}

# Subnets
resource "aws_subnet" "gwlb_subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "gwlb-subnet-1"
  }
}

resource "aws_subnet" "gwlb_subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "gwlb-subnet-2"
  }
}

# Gateway Load Balancer
resource "aws_lb" "gateway" {
  name               = "gateway-load-balancer"
  load_balancer_type = "gateway"

  subnet_mapping {
    subnet_id = aws_subnet.gwlb_subnet_1.id
  }

  subnet_mapping {
    subnet_id = aws_subnet.gwlb_subnet_2.id
  }

  enable_cross_zone_load_balancing = true

  tags = {
    Name = "gateway-load-balancer"
  }
}

# Target Group
resource "aws_lb_target_group" "gwlb_target_group" {
  name     = "gwlb-target-group"
  port     = 6081
  protocol = "GENEVE"
  vpc_id   = aws_vpc.main.id

  health_check {
    protocol            = "HTTP"
    port                = "80"
    path                = "/health"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 3
    unhealthy_threshold = 3
  }

  tags = {
    Name = "gwlb-target-group"
  }
}

# Listener
resource "aws_lb_listener" "gwlb_listener" {
  load_balancer_arn = aws_lb.gateway.arn

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.gwlb_target_group.arn
  }
}

# VPC Endpoint Service
resource "aws_vpc_endpoint_service" "gwlb_service" {
  acceptance_required        = false
  gateway_load_balancer_arns = [aws_lb.gateway.arn]

  tags = {
    Name = "gwlb-endpoint-service"
  }
}

# Outputs
output "gateway_load_balancer_arn" {
  description = "ARN of the Gateway Load Balancer"
  value       = aws_lb.gateway.arn
