terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = var.aws_region
}

variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "db_snapshot_identifier" {
  description = "The identifier of the DB snapshot to restore from"
  type        = string
}

variable "db_instance_identifier" {
  description = "The identifier for the DB instance"
  type        = string
  default     = "restored-db-instance"
}

variable "db_instance_class" {
  description = "The instance class for the RDS instance"
  type        = string
  default     = "db.t3.micro"
}

variable "db_subnet_group_name" {
  description = "The DB subnet group name"
  type        = string
  default     = null
}

variable "vpc_security_group_ids" {
  description = "List of VPC security group IDs"
  type        = list(string)
  default     = []
}

variable "publicly_accessible" {
  description = "Whether the DB instance is publicly accessible"
  type        = bool
  default     = false
}

variable "multi_az" {
  description = "Whether to enable Multi-AZ deployment"
  type        = bool
  default     = false
}

variable "storage_encrypted" {
  description = "Whether to enable storage encryption"
  type        = bool
  default     = true
}

variable "backup_retention_period" {
  description = "The backup retention period in days"
  type        = number
  default     = 7
}

variable "tags" {
  description = "Tags to apply to resources"
  type        = map(string)
  default     = {}
}

resource "aws_db_instance" "from_snapshot" {
  identifier     = var.db_instance_identifier
  instance_class = var.db_instance_class

  # Restore from snapshot
  snapshot_identifier = var.db_snapshot_identifier

  # Network configuration
  db_subnet_group_name   = var.db_subnet_group_name
  vpc_security_group_ids = var.vpc_security_group_ids
  publicly_accessible    = var.publicly_accessible

  # High availability
  multi_az = var.multi_az

  # Backup configuration
  backup_retention_period = var.backup_retention_period
  skip_final_snapshot     = true

  # Encryption
  storage_encrypted = var.storage_encrypted

  # Maintenance
  auto_minor_version_upgrade = true

  # Tags
  tags = merge(
    var.tags,
    {
      Name = var.db_instance_identifier
    }
  )
}

output "db_instance_endpoint" {
  description = "The connection endpoint for the DB instance"
  value       = aws_db_instance.from_snapshot.endpoint
}

output "db_instance_arn" {
  description = "The ARN of the DB instance"
  value       = aws_db_instance.from_snapshot.arn
}

output "db_instance_id" {
  description = "The ID of the DB instance"
  value       = aws_db_instance.from_snapshot.id
}

output "db_instance_address" {
  description = "The hostname of the RDS instance"
  value       = aws_db_instance.from_snapshot.address
}

output "db_instance_port" {
  description = "The port of the RDS instance"
  value       = aws_db_instance.from_snapshot.port
}

