terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 bucket containing the database backup
resource "aws_s3_bucket" "db_backup" {
  bucket = "my-database-backup-bucket"
}

# IAM role for RDS to access S3
resource "aws_iam_role" "rds_s3_import_role" {
  name = "rds-s3-import-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for S3 access
resource "aws_iam_role_policy" "rds_s3_import_policy" {
  name = "rds-s3-import-policy"
  role = aws_iam_role.rds_s3_import_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.db_backup.arn,
          "${aws_s3_bucket.db_backup.arn}/*"
        ]
      }
    ]
  })
}

# DB subnet group
resource "aws_db_subnet_group" "default" {
  name       = "main-subnet-group"
  subnet_ids = ["subnet-12345678", "subnet-87654321"] # Replace with your subnet IDs

  tags = {
    Name = "Main DB subnet group"
  }
}

# Security group for RDS
resource "aws_security_group" "rds" {
  name        = "rds-security-group"
  description = "Security group for RDS instance"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Replace with your CIDR block
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "RDS Security Group"
  }
}

# RDS instance restored from S3
resource "aws_db_instance" "restored_from_s3" {
  identifier     = "db-restored-from-s3"
  engine         = "mysql"
  engine_version = "8.0"
  instance_class = "db.t3.micro"

  allocated_storage     = 20
  max_allocated_storage = 100
  storage_type          = "gp3"
  storage_encrypted     = true

  db_name  = "mydb"
  username = "admin"
  password = "ChangeMe123!" # Use a secure password or AWS Secrets Manager

  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds.id]
  publicly_accessible    = false

  backup_retention_period = 7
  skip_final_snapshot     = true
  deletion_protection     = false

  s3_import {
    source_engine         = "mysql"
    source_engine_version = "8.0"
    bucket_name           = aws_s3_bucket.db_backup.id
    bucket_prefix         = "backups/"
    ingestion_role        = aws_iam_role.rds_s3_import_role.arn
  }

  tags = {
    Name = "RDS Instance Restored from S3"
  }

  depends_on = [aws_iam_role_policy.rds_s3_import_policy]
}

output "db_instance_endpoint" {
  description = "The connection endpoint for the RDS instance"
  value       = aws_db_instance.restored_from_s3.endpoint
}

output "db_instance_id" {
  description = "The RDS instance ID"
  value       = aws_db_instance.restored_from_s3.id
}

