provider "aws" {
  region = "us-east-1"
}

# Create a DB subnet group
resource "aws_db_subnet_group" "mysql_subnet_group" {
  name       = "mysql-subnet-group"
  subnet_ids = var.subnet_ids

  tags = {
    Name = "MySQL DB Subnet Group"
  }
}

# Create a security group for RDS
resource "aws_security_group" "mysql_sg" {
  name        = "mysql-security-group"
  description = "Security group for MySQL RDS instance"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "MySQL Security Group"
  }
}

# Create MySQL RDS instance
resource "aws_db_instance" "mysql" {
  identifier             = "mysql-instance"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  db_name                = "mydb"
  username               = "admin"
  password               = var.db_password
  parameter_group_name   = "default.mysql8.0"
  db_subnet_group_name   = aws_db_subnet_group.mysql_subnet_group.name
  vpc_security_group_ids = [aws_security_group.mysql_sg.id]
  skip_final_snapshot    = false
  final_snapshot_identifier = "mysql-final-snapshot-${formatdate("YYYY-MM-DD-hhmm", timestamp())}"
  backup_retention_period = 7
  publicly_accessible    = false

  tags = {
    Name = "MySQL RDS Instance"
  }
}

# Create a snapshot of the MySQL instance
resource "aws_db_snapshot" "mysql_snapshot" {
  db_instance_identifier = aws_db_instance.mysql.identifier
  db_snapshot_identifier = "mysql-snapshot-${formatdate("YYYY-MM-DD-hhmm", timestamp())}"

  tags = {
    Name = "MySQL Instance Snapshot"
  }
}

# Variables
variable "vpc_id" {
  description = "VPC ID where the RDS instance will be created"
  type        = string
}

variable "subnet_ids" {
  description = "List of subnet IDs for the DB subnet group"
  type        = list(string)
}

variable "db_password" {
  description = "Password for the MySQL database"
  type        = string
  sensitive   = true
}

# Outputs
output "db_instance_endpoint" {
  description = "The connection endpoint for the MySQL instance"
  value       = aws_db_instance.mysql.endpoint
}

output "db_instance_id" {
  description = "The identifier of the MySQL instance"
  value       = aws_db_instance.mysql.id
}

output "db_snapshot_id" {
  description = "The identifier of the database snapshot"
  value       = aws_db_snapshot.mysql_snapshot.id
}

